(function ($) {

    $.fn.longTap = function (args) {

        var plugin = function () {

            var pluginInstanceStorage = {
                selected: 0,
                quickMode: false,
                allowQuickMode: args.allowQuickMode || true
            }

            var preventClick = args.preventClick || true;
            var preventSelect = args.preventSelect || true;
            var preventContext = args.preventContext || true;

            return function (key, self) {
                var $self = $(self);
                $self.storage = pluginInstanceStorage;

                var timer = undefined;
                var startTimer = undefined;

                var isSelected = false;
                var isPreStart = false;

                var isTapStart = false;
                var isTapStartStamp = 0;

                var clearingTimers = function (variable, clearCallback, event, stopFlag) {
                    if (!!variable) {
                        clearCallback();

                        // call onstop callback
                        if (args.onStop) {
                            if (stopFlag) {
                                args.onStop(event, $self);
                            }
                        }
                    }
                };

                var timeouts = {
                    mainDelay: args.timeout || 300,
                    mainDelayClear: function () {
                        clearTimeout(timer);
                        timer = undefined;
                    },

                    onStartDelay: args.onStartDelay || 10,
                    onStartDelayClear: function () {
                        clearTimeout(startTimer);
                        startTimer = undefined;
                    },
                };

                var handlers = {
                    // handle select or unselect
                    success: function (event) {
                        if (isSelected) {
                            pluginInstanceStorage.selected--;

                            if (args.onReject) {
                                args.onReject(event, $self);
                            }

                            // disable quick select mode
                            if (pluginInstanceStorage.selected == 0) {
                                pluginInstanceStorage.quickMode = false;
                            }
                        } else {
                            pluginInstanceStorage.selected++;

                            if (args.onSuccess) {
                                args.onSuccess(event, $self);
                            }

                            // enable quick select mode
                            if (pluginInstanceStorage.allowQuickMode) {
                                if (pluginInstanceStorage.selected > 0) {
                                    pluginInstanceStorage.quickMode = true;
                                }
                            }
                        }

                        isSelected = !isSelected;
                        isPreStart = false;

                        timeouts.mainDelayClear();
                    },

                    // thats stop longtap event
                    stop: function (event) {
                        clearingTimers(startTimer, timeouts.onStartDelayClear, event);
                        clearingTimers(timer, timeouts.mainDelayClear, event, true);
                    },

                    // just an wrapper for killEvent, add firing callback
                    override: function (callback, preventFlag) {
                        return function (event) {
                            if (callback) {
                                callback(event, $self);
                            }

                            if (preventFlag) {
                                events.killEvent(event);
                            }
                        };
                    }
                };

                var events = {
                    killEvent: function (event) {
                        event.preventDefault();
                        return;
                    },

                    scrolling: function (event) {
                        // prevent stopping, if tap started
                        if (isPreStart == false) {
                            handlers.stop(event);
                        }

                        // if 'click' start, but we scroll
                        if (isTapStart) {
                            isTapStart = false;
                        }
                    },

                    tapStart: function (event) {
                        isTapStart = true;
                        isTapStartStamp = performance.now();

                        event.stopPropagation();

                        startTimer = setTimeout(function () {
                            event.preventDefault();
                            isPreStart = true;

                            if (args.onStart) {
                                args.onStart(event, $self);
                            }

                            timer = setTimeout(handlers.success, timeouts.mainDelay, event);
                            timeouts.onStartDelayClear();
                        }, timeouts.onStartDelay);
                    },

                    tapEnd: function (event, self) {

                        if (isTapStart) {
                            isTapStart = false;

                            // if 'click' happen
                            if ((performance.now() - isTapStartStamp) <= 300) {
                                if (pluginInstanceStorage.quickMode) {
                                    handlers.success(event);
                                }
                            }
                        }

                        if (event.cancelable) {
                            event.preventDefault();
                        }
                        handlers.stop(event);
                    }
                };

                $self.off('contextmenu selectstart touchmove touchstart touchend');

                /*$self.on('click', 
                    handlers.override(args.onClick, preventClick)
                );*/

                $self.on('contextmenu',
                    handlers.override(args.onContext, preventContext)
                );

                $self.on('selectstart',
                    handlers.override(args.onSelect, preventSelect)
                );

                $self.on('touchmove', events.scrolling);
                $self.on('touchstart', events.tapStart);
                $self.on('touchend', events.tapEnd);

            }
        }

        return this.each(plugin());

    }

})(jQuery);


(function ($) {
    "use strict";
    $.fn.openSelect = function () {
        return this.each(function (idx, domEl) {
            if (document.createEvent) {
                var event = document.createEvent("MouseEvents");
                event.initMouseEvent("mousedown", true, true, window, 0, 0, 0, 0, 0, false, false, false, false, 0, null);
                domEl.dispatchEvent(event);
            } else if (element.fireEvent) {
                domEl.fireEvent("onmousedown");
            }
        });
    }
}(jQuery));

(function ($) {
    $.fn.innerText = function (msg) {
        if (msg) {
            if (document.body.innerText) {
                for (var i in this) {
                    this[i].innerText = msg;
                }
            } else {
                for (var i in this) {
                    this[i].innerHTML.replace(/&lt;br&gt;/gi, "n").replace(/(&lt;([^&gt;]+)&gt;)/gi, "");
                }
            }
            return this;
        } else {
            if (document.body.innerText) {
                return this[0].innerText;
            } else {
                return this[0].innerHTML.replace(/&lt;br&gt;/gi, "n").replace(/(&lt;([^&gt;]+)&gt;)/gi, "");
            }
        }
    };
})(jQuery);

(function ($) {

    var imodal = new Object();

    imodal.moving = false;
    imodal.open = false;
    imodal.fxIn = 'fadeInUp';//(isMobile.phone) ? 'fadeInUp' : 'fadeIn';
    imodal.fxOut = 'fadeOutDown';//(isMobile.phone) ? 'fadeOutDown' : 'fadeOut';

    imodal.hide = function (el, callback) {

        el.trigger('inc.imodal.hide');
        //el.hide();
        imodal.backdrop({
            action: 'hide',
            modalel: el
        });

        el.removeClass(imodal.fxIn).addClass(imodal.fxOut);


        setTimeout(function () {
            el.removeClass(imodal.fxOut).addClass(imodal.fxIn);

            el.hide().trigger('inc.imodal.hidden');
            imodal.moving = false;
            imodal.open = false;
            callback && callback();
        }, (window.appConfigObj[0].noAnimate ? 0 : 300));


    };

    imodal.backdrop = function (ops) {
        $el = $('#backdrop');
        $el.remove();

        if (ops.action == 'hide') {
            /*$el.removeClass('fadeIn').addClass('fadeOut');
            setTimeout(function(){
                $el.remove();
            },300);*/
        } else {
            var blur = '';

            if (!isMobile.any) {
                blur = '';
            }

            if (isMobile.phone && ncmHelpers.valid(ops, 'el')) {
                if (ops.el.data('backdrop') == 1) {
                    blur = 'justblur';
                }
            }

            var html = ' <div id="backdrop" class="animated bg-black-opacity-6 speed-4x fadeIn ' + blur + '" style="width: 100%; top:0; bottom:0; height:100%; position:absolute; z-index: 988;"></div>';
            $('body').append(html);

            $el.one('click', function () {
                $el.remove();
            });
        }

    };

    imodal.show = function (el) {
        thalog('showing imodal ', el);

        if (!el.is(':visible')) {
            if (!imodal.moving && !imodal.open) {
                imodal.moving = true;
                imodal.open = true;
                el.trigger('inc.imodal.show');

                if (!isMobile.phone) {
                    /*imodal.backdrop({
                        action  : 'show'
                    });*/
                } else {
                    if (el.data('backdrop')) {
                        imodal.backdrop({
                            action: 'show',
                            modalel: el
                        });
                    }

                    el.addClass(imodal.fxIn);
                }

                setTimeout(function () {
                    el.show();
                    el.trigger('inc.imodal.shown');
                }, 50);


                setTimeout(function () {
                    imodal.moving = false;
                    if (!isMobile.phone && !ncmMenu.open) {
                        imodal.backdrop({
                            action: 'show',
                            modalel: el
                        });
                    }
                }, (window.appConfigObj[0].noAnimate ? 0 : 300));


                ncmUIX.setStatusBar();

                ncmEvents.a();
            } else {
                imodal.moving = false;
                imodal.open = false;
            }
        }
    };

    imodal.action = function ($this) {
        var $content = $this.find('div.imodal-content');
        var handle = '';
        if (isMobile.phone) {
            var contH = $content.actual('height');

            if (contH >= ncmUIX.windowH || $content.hasClass('noPopup')) {
                var topM = '5px';
            } else {
                var topM = (ncmUIX.windowH - 250) + 'px';

                if (contH > 250) {
                    topM = (ncmUIX.windowH - contH) + 'px';
                    $this.find('div.imodal-body').append('<div class="col-xs-12" style="padding:50px;"></div>');//si el modal es mayor a 250px añado un spacer abajo del contenido para activar el scroll
                }
            }

            if ($content.hasClass('isPopup')) {
                var isDk = (ncmUIX.isDarkMode) ? 'lt' : 'dk';
                handle = '<div class="col-xs-12 wrapper text-right">' +
                    '   <a href="#" class="block imodalclose" style="background: url(/assets/images/modal_handle_' + isDk + '.png) no-repeat center top">' +
                    '       <i class="material-icons md-24 imodalclose">close</i>' +
                    '   </a>' +
                    '</div>';

                if (!$.trim($this.find('div.imodal-header').html())) {
                    $this.find('div.imodal-header').html(handle);
                }
            }

        } else {
            var topM = '20px';
        }

        $content.css('margin-top', topM);

        if (isMobile.any) {
            $this.off('scroll').on('scroll', function () {
                var top = $(this).scrollTop();
                if (top < -90) {
                    imodal.hide($this);

                    $this.trigger('inc.imodal.dismiss');
                }
            });
        }

        ncmHelpers.onClickWrap('.imodal, #backdrop', function (event, tis) {
            if (!$('.imodal, #backdrop').hasClass('fixedModal')) {
                imodal.hide($this);
                $this.trigger('inc.imodal.dismiss');
            }
        }, true);

        ncmHelpers.onClickWrap('.imodalclose', function (event, tis) {
            imodal.hide($this);
            $this.trigger('inc.imodal.dismiss');
        }, true);
    }

    $.fn.imodal = function (action, callback) {
        thalog('imodal fn');
        var $el = $(this);

        if (!$el.length) {
            return false;
        }

        if (action == 'hide') {
            imodal.hide($el, callback);
        } else if (action == 'listen') {
            //nada hago es solo para listen en imodaler
        } else {
            if ($('.imodal').is(':visible') || imodal.open) {
                //if(!imodal.moving){
                imodal.hide($('.imodal'), function () {
                    setTimeout(function () {
                        imodal.show($el);
                        imodal.action($el);
                    }, 70);
                });
                //}
            } else {
                imodal.show($el);
                imodal.action($el);
            }
        }
    };

}(jQuery));

(function ($) {
    $.fn.clickToggle = function (func1, func2) {
        var funcs = [func1, func2];
        this.data('toggleclicked', 0);
        this.click(function () {
            var data = $(this).data();
            var tc = data.toggleclicked;
            $.proxy(funcs[tc], this)();
            data.toggleclicked = (tc + 1) % 2;
        });
        return this;
    };
}(jQuery));

(function ($) {
    $.fn.afterAnimation = function (callback) {
        thalog('afterAnimation plgn');

        if (window.appConfigObj[0].noAnimate) {
            return this.each(function () {
                callback && callback($(this));
            });
        } else {
            setTimeout(() => {
                return this.each(function () {
                    callback && callback($(this));
                });
            }, 300);
        }

        return false;

        if (window.appConfigObj[0].noAnimate) {
            return this.each(function () {
                callback && callback($(this));
            });
        } else {
            return this.each(function () {

                var t, el = document.createElement("fakeelement"), transitionEvent;

                var transitions = {
                    "transition": "transitionend",
                    "OTransition": "oTransitionEnd",
                    "MozTransition": "transitionend",
                    "WebkitTransition": "webkitTransitionEnd",

                    "animation": "animationend",
                    "OAnimation": "oAnimationEnd",
                    "MozAnimation": "animationend",
                    "WebkitAnimation": "webkitAnimationEnd"
                }

                for (t in transitions) {
                    if (el.style[t] !== undefined) {
                        transitionEvent = transitions[t];
                    }
                }

                //'webkitAnimatinEnd oAnimationEnd MSAnimationEnd animationend transitionend webkitTransitionEnd oTransitionEnd MSTransitionEnd'
                $(this).one(transitionEvent, function () {
                    callback && callback($(this));
                });

            });
        }

    };
}(jQuery));

(function ($) {
    $.fn.once = function (a, b) {
        return this.each(function () {
            $(this).off(a).on(a, b);
        });
    };
}(jQuery));

(function ($) {
    $.fn.codeScanner = function (options) {
        var settings = $.extend({}, $.fn.codeScanner.defaults, options);

        return this.each(function () {
            var pressed = false;
            var chars = [];
            var $input = $(this);

            $(window).off('keypress').on('keypress', function (e) {
                var keycode = (e.which) ? e.which : e.keyCode;
                if ((keycode >= 65 && keycode <= 90) ||
                    (keycode >= 97 && keycode <= 122) ||
                    (keycode >= 48 && keycode <= 57)
                ) {
                    chars.push(String.fromCharCode(e.which));
                }
                // console.log(e.which + ":" + chars.join("|"));
                if (pressed == false) {
                    setTimeout(function () {
                        if (chars.length >= settings.minEntryChars) {
                            var barcode = chars.join('');
                            settings.onScan($input, barcode);
                        }
                        chars = [];
                        pressed = false;
                    }, settings.maxEntryTime);
                }
                pressed = true;
            });

            $input.keypress(function (e) {
                if (e.which === 13) {
                    e.preventDefault();
                }
            });

            return $(this);
        });
    };

    $.fn.codeScanner.defaults = {
        minEntryChars: 8,
        maxEntryTime: 100,
        onScan: function ($element, barcode) {
            $element.val(barcode);
        }
    };
})(jQuery);

