var imodaler = function (options) {
    var $el = options.element;
    var showHide = 'show';

    if (ncmHelpers.valid(options, 'hide')) {
        showHide = 'hide';
        $el.on('inc.imodal.hidden', function () {
            if (!ncmHelpers.valid(options, 'noOff')) {
                $(this).off('inc.imodal.hidden');
            }

            options.onHidden && options.onHidden($(this));
        }).imodal('hide');
        return false;
    } else if (ncmHelpers.valid(options, 'listen')) {
        showHide = 'listen';
    }

    var less = 1;
    $('.imodal:visible').each(function () {
        $(this).css('z-index', (1000 - less) + 'px');
        less++;
    });

    if ($el.is(':visible')) {
        if (ncmHelpers.valid(options, 'content')) {
            $(this).find('.imodal-body').html(options.content);
        }

        if (ncmHelpers.valid(options, 'contentNoWrap')) {
            $(this).find('.imodal-body').removeClass('wrapper').addClass('no-padder');
        }

        if (ncmHelpers.valid(options, 'contentWrap')) {
            options.contentNoWrap = false;
            $(this).find('.imodal-body').addClass('wrapper').removeClass('no-padder');
        }
    }

    if (!ncmHelpers.valid(options, 'noOff')) {
        $el.off('inc.imodal.show inc.imodal.shown inc.imodal.dismiss inc.imodal.hidden');
    }

    if (ncmHelpers.valid(options, 'noBgColor')) {
        $el.find('.imodal-content').removeClass('bg-white bg-light bg-dark bg-black lt lter bg dk dker');
    }

    ncmUIX.setPopupClass($el.find('div.imodal-content'));

    $el.on('inc.imodal.show', function () {
        if (!ncmHelpers.valid(options, 'noOff')) {
            $(this).off('inc.imodal.show');
        }

        options.onBefore && options.onBefore($(this));

        if (ncmHelpers.valid(options, 'content')) {
            $(this).find('.imodal-body').html(options.content);
        }
        if (ncmHelpers.valid(options, 'contentNoWrap')) {
            $(this).find('.imodal-body').removeClass('wrapper').addClass('no-padder');
        }
        if (ncmHelpers.valid(options, 'contentWrap')) {
            options.contentNoWrap = false;
            $(this).find('.imodal-body').addClass('wrapper').removeClass('no-padder');
        }

        ncmHelpers.bitrix.hideChat();
    }).on('inc.imodal.shown', function () {
        if (!ncmHelpers.valid(options, 'noOff')) {
            $(this).off('inc.imodal.shown');
        }

        options.onAfter && options.onAfter($(this));
        ncmEvents.a();

        if (ncmHelpers.valid(options, 'fixed')) {
            $('#backdrop').addClass('fixedModal');
            $el.addClass('fixedModal');
        } else {
            $('#backdrop').removeClass('fixedModal');
            $('.imodal').removeClass('fixedModal');
        }

        if (ncmHelpers.valid(options, 'lightBg')) {
            $('#backdrop').removeClass('bg-black-opacity-5');
        } else {
            $('#backdrop').addClass('bg-black-opacity-7');
        }

        $(this).on('inc.imodal.dismiss', function () {
            if (!ncmHelpers.valid(options, 'noOff')) {
                $(this).off('inc.imodal.dismiss');
            }
            options.onDismiss && options.onDismiss($(this));
        }).on('inc.imodal.hidden', function () {
            ncmEvents.unHashUrl();

            if (!ncmHelpers.valid(options, 'noOff')) {
                $(this).off('inc.imodal.hidden');
            }

            options.onHidden && options.onHidden($(this));

            if (ncmHelpers.valid(options, 'empty')) {
                $(this).find('.imodal-body').html('');
            }

            if (ncmHelpers.valid(options, 'contentNoWrap')) {
                $(this).find('.imodal-body').addClass('wrapper').removeClass('no-padder');
            }
        });
    }).imodal(showHide);
};

