function simulateKeyPress(character, el) {
    //jQuery.event.trigger({ type : 'keypress', which : character.charCodeAt(0) });
    var press = jQuery.Event(window.keyEvent);
    press.which = character.charCodeAt(0);
    el.trigger(press);
}

var softKeyboardManager = function (options) {
    var numberel = '#softNumberKeyboard';
    var qwertyel = '#softQwertyKeyboard';
    var numericMode = (options.numeric) ? true : false;
    var kbrd = (options.numeric) ? numberel : qwertyel;
    var $kbrd = $(kbrd);
    var btnel = kbrd + ' a';
    var $target = iftn(options.element, $(document));
    var isReadOnly = $target.attr('readonly');
    var inputType = $target.attr('type');

    if (inputType == 'tel' || inputType == 'number') {//si es input tel fuerzo a number pad
        $kbrd = $(numberel); //muestro el teclado numerico
        numericMode = false; //esto hace que use el mecanismo de escritura del teclado alfanumerico
        btnel = numberel + ' a';
    } else if ($.inArray(inputType, ['month', 'date', 'datetime', 'checkbox']) > -1) {
        return false;
    }

    resetOps();

    function showOps(callback) {
        if (!$kbrd.is(':visible')) {
            $kbrd.show();

            if (options.canClose) {
                $kbrd.find('[data-key="close"]').removeClass('hidden');
            }

            ncmHelpers.onClickWrap(btnel, function (event, tis) {
                var key = tis.data('key') + "";

                if (numericMode) {
                    if (key == 'close') {
                        softKeyboardManager({ action: 'hide', element: $target });
                    } else if (key == 'enter') {
                        simulateKeyPress('\r', $(document));
                    } else if (key == 'backspace') {
                        simulateKeyPress('\b', $(document));
                    } else {
                        simulateKeyPress(key, $(document));
                    }
                } else {
                    var current = $target.val();

                    if (key == 'close') {
                        softKeyboardManager({ action: 'hide', element: $target });
                        key = '';
                    } else if (key == 'enter') {
                        key = '\r';
                    } else if (key == 'space') {
                        key = ' ';
                    } else if (key == 'backspace') {
                        if (current.length > 1) {
                            current = current.slice(0, -1);
                        } else {
                            current = ' ';
                        }
                        key = '';
                    }
                    var newText = (current + key).toUpperCase();
                    triggerInputKeyEvent($target, newText);
                }
            });

            $target.trigger('ncm.vk.shown');

            callback && callback();
        }
    }

    function hideOps(callback) {
        //$(numberel + ', ' + qwertyel).hide();
        //$kbrd.hide();
        $target.trigger('ncm.vk.hidden');
        callback && callback();
    }

    function resetOps() {
        //if($kbrd.is(':visible')){
        $(numberel + ', ' + qwertyel).hide();
        //}
    }

    if (options.action == 'show') {
        if ((!isMobile.any && !window.appConfigObj[0].virtualKeyboard) || (!options.numeric && isMobile.any) || isReadOnly) {
            return false;
        }
        showOps(options.onShow);
    } else if (options.action == 'hide') {
        hideOps(options.onHide);
    } else {//auto detect
        if ($kbrd.is(':visible')) {
            hideOps(options.onHide);
        } else {
            showOps(options.onShow);
        }
    }
};

var softKeyboardListener = function (end) {
    if (end) {
        $('input, textarea, [contenteditable="true"]').off('focus click');
        return true;
    }

    $('input, textarea, [contenteditable="true"]').off('focus').on('focus', function () {
        softKeyboardManager({ action: 'show', numeric: false, element: $(this), canClose: true });
    });
};

var ncmMenu = {
    over: $('#menu'),
    backDrop: $('#menuBackDrop'),
    leftBlock: $('#menu .leftBlock'),
    rightBlock: $('#menu .rightBlock'),
    rightBlock2: $('#menu .rightBlock2'),
    moving: false,
    open: false,
    inMyMenu: false,
    animIn: (isMobile.phone) ? 'slideInLeft' : 'slideInLeft',
    animOut: (isMobile.phone) ? 'slideOutLeft' : 'slideOutLeft',
    manager: function (action, callback, onHidden) {

        if (action == 'hide') {
            if (!ncmMenu.moving && ncmMenu.open) {
                ncmMenu.hideMenu(callback, onHidden);
            } else {
                callback && callback();
            }
        } else if (action == 'show') {
            if (!ncmMenu.moving && !ncmMenu.open) {
                ncmMenu.showMenu(callback);
            } else {
                callback && callback();
            }

        } else {
            if (ncmMenu.open) {
                ncmMenu.hideMenu(callback, onHidden);
            } else {
                ncmMenu.showMenu(callback);
            }
        }
    },
    hideMenu: function (callback, onHidden) {
        if (ncmAuth.isResource) {
            ncmAuth.isResource = false;
            ncmAuth.unLoadNewUser();
            return false;
        }

        ncmMenu.moving = true;

        ncmMenu.backDrop.hide();

        setTimeout(function () {
            ncmMenu.moving = false;
            ncmMenu.open = false;
            ncmMenu.over.hide();
            ncmEvents.a();
            ncmMenu.over.trigger("ncmMenu.close");
            ncmEvents.unHashUrl();
            callback && callback();
            onHidden && onHidden();
        }, (window.appConfigObj[0].noAnimate ? 0 : 150));

        ncmUIX.setStatusBar();

        currentSaleModeUI();

        ncmHelpers.bitrix.hideChat();
    },
    showMenu: function (callback) {
        ncmMenu.moving = true;
        ncmModules.hide();
        ncmMenu.setTime();
        ncmUIX.setStatusBar(true);
        //ncmMenu.backDrop.show();

        setTimeout(function () {
            ncmMenu.leftBlock.addClass(ncmMenu.animIn).removeClass(ncmMenu.animOut);
            ncmMenu.rightBlock.addClass('slideInRight').removeClass('slideOutRight');
            ncmMenu.rightBlock2.addClass('fadeIn').removeClass('fadeOut');
            ncmMenu.over.show();
            ncmMenu.setContent();

            setTimeout(function () {
                ncmHelpers.bitrix.showChat();
            }, 800);

            ncmMenu.over.trigger("ncmMenu.show");
        }, 50);

        setTimeout(function () {
            ncmMenu.moving = false;
            ncmMenu.open = true;

            var menuTuts = ncmStorage.getEntry('pointMenuTutorial');
            if (!menuTuts) {
                ncmTutorial.start('pointMenu');
                ncmStorage.addEntry('pointMenuTutorial', true);
            }

            callback && callback();
        }, 200);

        if (isMobile.phone) {

            $('.ncmMyMenuOrders').attr('href', window.standAloneUrl + 'userOrders?s=' + window.btoa(ncmGlobals.settings[0].companyId + ',' + ncmAuth.activeUser.activeUserId));
            $('.ncmMyMenuSchedule').attr('href', window.standAloneUrl + 'userAgenda?s=' + window.btoa(ncmGlobals.settings[0].companyId + ',' + ncmAuth.activeUser.activeUserId));
            $('.ncmMyMenuPanel').attr('href', '/login?token=' + ncmAuth.activeUser.token);

            $('.mainMenuContent').addClass('hidden');
            $('.menuToolsBtn').removeClass('hidden');
            $('#ncmMenuUserInfo').addClass('hidden');
            $('.secondMenuContentBack,.secondMenuContent').removeClass('hidden');

            //$('[data-type="refreshDB"]').addClass('hidden');
            //$('[data-type="syncList"]').addClass('hidden');
            //$('[data-type="tutorial"]').addClass('hidden');
            //$('.hideMenuX[data-type="hideMenu"]').addClass('hidden');

            /*Intercom('update', {
              hide_default_launcher : true
            });*/

            ncmMenu.setContent();

            ncmMenu.inMyMenu = true;

            ncmUIX.myMenu.events();
        }


    },
    setTime: function () {
        var hour = moment().format('HH:mm');
        var date = moment().format('dddd, D MMM YYYY');
        $('#ncmMenuTime .notifyHour').text(hour);
        $('#ncmMenuTime .notifyDate').text(date);
    },
    setContent: () => {
        var $wrapper = $('#registerWrapper'),
            $top = $('#topMainMenu'),
            $body = $('#bodyMainMenu'),
            $foot = $('#footMainMenu'),
            viewH = $wrapper.outerHeight(),
            topH = $top.data('height'),
            bodyH = $body.data('height'),
            footH = $foot.data('height');

        var paddr = viewH - (topH + bodyH + footH),
            paddrPart = paddr / 2;

        if (isMobile.phone) {
            $('#bodyMainMenu a').removeClass('h3 wrapper-md').addClass('h4 wrapper');
            $('#topMainMenuBtnOps').removeClass('text-right').addClass('text-center');
            $('#topMainMenuBtnOps > a.clickeable.m-l-md.hidden-tablet').hide();
            $('#topMainMenuBtnOps .material-icons').removeClass('md-24');
        } else if (isMobile.tablet) {
            $('#topMainMenuBtnOps > a.clickeable.m-l-md.hidden-tablet').hide();
            $body.css({ 'padding': paddrPart + 'px 0' });
        } else {
            $body.css({ 'padding': paddrPart + 'px 0' });
        }
    },
    setContents: function () {
        var menuInfoTop = 168;
        var menuInfoBottom = (ncmGlobals.settings[0].spotify) ? 125 : 0;
        var menuInfoBody = ncmUIX.windowH - (menuInfoTop + menuInfoBottom + 15);

        $('.menuInfoBody').height(menuInfoBody + 'px');

        var menuExtraSpace = 60;//(isMobile.phone) ? 210 : 140;

        var menuBody = $('#ncmMenuListBlock').outerHeight();
        var menuBottom = $('#ncmMenuListFoot').outerHeight();
        var menuThaHeight = (menuBody + menuBottom) + menuExtraSpace;

        $('#ncmMenuListBlockSpacer').height((ncmUIX.windowH - menuThaHeight) + 'px');

        var bodyMainMenuMT = $('#bodyMainMenu').data('margin-top'),
            footMainMenuMT = $('#footMainMenu').data('margin-top'),
            bodyMainMenuH = $('#bodyMainMenu').data('height'),
            footMainMenuH = $('#footMainMenu').data('height');

        if (isMobile.phone) {
            $('#bodyMainMenu').css({ 'max-height': bodyMainMenuH + 'vh' });
            $('#bodyMainMenu a').removeClass('h3 wrapper-md').addClass('h4 wrapper');
            $('#topMainMenuBtnOps').removeClass('text-right').addClass('text-center');
            $('#topMainMenuBtnOps [data-type="goFullScreen]').hide();
            $('#topMainMenuBtnOps .material-icons').removeClass('md-24');
        } else if (isMobile.tablet) {
            $('#bodyMainMenu').css({ 'margin-top': bodyMainMenuMT + 'vh' });
            $('#footMainMenu').css({ 'margin-top': footMainMenuMT + 'vh' });
            $('#bodyMainMenu #topMainMenuBtnOps [data-type="goFullScreen]').hide();
        } else {
            $('#bodyMainMenu').css({ 'margin-top': bodyMainMenuMT + 'vh' });
            $('#footMainMenu').css({ 'margin-top': footMainMenuMT + 'vh' });
        }
    }
};

var ncmActionSheet = {
    el: $('#actionSheet'),
    backdrop: $('#backdropOps'),
    visible: false,
    moving: false,
    setStyle: function () {
        var head = '<a href="#" class="block asClose" style="background: url(/assets/images/modal_handle_' + ((ncmUIX.isDarkMode) ? 'lt' : 'dk') + '.png) no-repeat center top">' +
            '   <i class="material-icons md-24 asClose">close</i>' +
            '</a>';
        $('#actionSheetHead').html(head);
    },
    action: function () {
        ncmEvents.a(function () {
            ncmActionSheet.hide();
        });

        ncmHelpers.onClickWrap('.asClose', function () {
            ncmActionSheet.hide();
        });

        if (isMobile.any) {
            $('#actionSheet').off('scroll').on('scroll', function () {
                var top = $(this).scrollTop();
                if (top < -90) {
                    ncmActionSheet.hide();
                }
            });
        }
    },
    show: function (content, callback) {
        ncmActionSheet.setStyle();

        if (!ncmActionSheet.visible && !ncmActionSheet.moving) {
            ncmActionSheet.el.find('div.actionSheetContent').html(content);
            ncmActionSheet.moving = true;
            ncmActionSheet.el.show();
            ncmActionSheet.backdrop.show();
        } else {
            ncmActionSheet.el.find('div.actionSheetContent').html(content);
        }

        ncmActionSheet.action();

        var bodyH = $('#actionSheetBody').height();
        if (isMobile.phone) {
            bodyH -= 80;
        } else {
            bodyH += 20;
        }

        if (bodyH > ncmUIX.windowH) {
            var margin = 0;
            //$('#actionSheetBody').addClass('momentumit').height(ncmUIX.windowH + 'px');
        } else {
            var margin = ncmUIX.windowH - bodyH;
        }

        $('#actionSheetBody').css('margin-top', margin + 'px');

        setTimeout(function () {
            ncmActionSheet.moving = false;
            ncmActionSheet.visible = true;
            ncmActionSheet.el.trigger("ncmActionSheet.open");
            callback && callback();
        }, (window.appConfigObj[0].noAnimate ? 0 : 300));
    },
    hide: function (callback) {
        if (!ncmActionSheet.moving) {
            ncmActionSheet.moving = true;
            ncmActionSheet.el.removeClass('fadeInUp').addClass('fadeOutDown');
            ncmActionSheet.backdrop.hide();

            setTimeout(function () {
                ncmActionSheet.moving = false;
                ncmActionSheet.visible = false;
                ncmActionSheet.el.hide();
                ncmActionSheet.el.removeClass('fadeOutDown').addClass('fadeInUp');
                //ncmActionSheet.el.find('div.actionSheetContent').html('');
                ncmActionSheet.el.trigger("ncmActionSheet.close");
                callback && callback();
            }, (window.appConfigObj[0].noAnimate ? 0 : 300));
        }
    },
    auto: function (callback) {
        if (ncmActionSheet.visible) {
            ncmActionSheet.hide(callback);
        } else {
            ncmActionSheet.show(callback);
        }
    }
};

var ncmModules = {
    btn: $('#modulesBtn'),
    list: $('#modulesMenu'),
    symbol: $('#modulesBtn i.toggleSymbol'),
    backdrop: $('#backdropOps'),
    visible: false,
    show: function (callback) {
        if (!ncmModules.btn.hasClass('active') && !ncmModules.btn.hasClass('disabled')) {
            ncmModules.list.show();
            ncmModules.btn.addClass('active');
            ncmModules.btn.find('.addIcon').hide(function () {
                ncmModules.btn.find('.closeIcon').show();
            });
            ncmModules.backdrop.show();
            ncmModules.visible = true;
            callback && callback();

        }
    },
    hide: function (goBack, callback) {
        if (ncmModules.btn.hasClass('active')) {
            ncmModules.backdrop.hide();
            if (ncmModules.list.is(':visible')) {
                ncmModules.list.addClass('animated fadeOutDown speed-5x').afterAnimation(function () {
                    ncmModules.list.removeClass('animated fadeOutDown speed-5x').hide();
                });

                ncmModules.btn.removeClass('active');

                ncmModules.btn.find('.addIcon').show();
                ncmModules.btn.find('.closeIcon').hide();
                if (goBack) {
                    ncmSettings.setDefaultModuleView('load');
                }
                ncmModules.visible = false;
                callback && callback();

            } else {
                ncmModules.btn.removeClass('active');
                ncmModules.btn.find('.addIcon').show();
                ncmModules.btn.find('.closeIcon').hide();
                if (goBack) {
                    //ncmHotKeys.build('uiReset');
                    ncmSettings.setDefaultModuleView('load');
                }
                callback && callback();
            }
        }
    },
    auto: function (callback) {
        if (ncmModules.visible) {
            ncmModules.hide(callback);
        } else {
            ncmModules.show(callback);
        }
    },
    load: function (callback) {
        if (ncmGlobals.settings[0].storeTables) {
            $('#modulesMenu .tablesModulesBtn').show();
        } else {
            $('#modulesMenu .tablesModulesBtn').hide();
        }
        if (ncmGlobals.settings[0].calendar) {
            $('#modulesMenu .calendarModulesBtn').show();
        } else {
            $('#modulesMenu .calendarModulesBtn').hide();
        }
        if (ncmGlobals.settings[0].ordersPanel) {
            $('#modulesMenu .ordersModulesBtn').show();
        } else {
            $('#modulesMenu .ordersModulesBtn').hide();
        }
        if (!ncmGlobals.settings[0].storeTables && !ncmGlobals.settings[0].calendar && !ncmGlobals.settings[0].ordersPanel && !isMobile.phone.any) {
            $('#modulesMenu').hide();
            $('#modulesBtnMain').hide();
        } else {
            $('#modulesBtnMain')
                .data('type', 'modulesMenu')
                .data('original-title', 'Módulos')
                .attr('title', 'Módulos')
                .find('.addIcon')
                .removeClass('text-danger')
                .text('add');
        }
    },
    back: function (callback) {
        if (!ncmModules.btn.hasClass('active') && !ncmModules.btn.hasClass('disabled')) {

            ncmModules.btn.addClass('active');
            ncmModules.btn.find('.addIcon').hide(function () {
                ncmModules.btn.find('.closeIcon').show();
            });
            callback && callback();
        }
    }
};

var modulesManager = function (action, callback) {
    var $btn = $('#modulesBtn');
    var $list = $('#modulesMenu');
    var $symbol = $('#modulesBtn i.toggleSymbol');

    function showMods(callback) {
        if (!$btn.hasClass('active') && !$btn.hasClass('disabled')) {
            $list.show();
            $btn.addClass('active');
            $btn.find('.addIcon').hide(function () {
                $btn.find('.closeIcon').show();
            });
            ncmModules.backdrop.show();
            callback && callback();
        }
    }

    function backMods(callback) {
        if (!$btn.hasClass('active') && !$btn.hasClass('disabled')) {

            $btn.addClass('active');
            $btn.find('.addIcon').hide(function () {
                $btn.find('.closeIcon').show();
            });
            callback && callback();

        }
    }

    function hideMods(goBack, callback) {
        if ($btn.hasClass('active')) {
            $('#backdropOps').hide();
            if ($list.is(':visible')) {
                $list.addClass('animated fadeOutDown speed-5x').afterAnimation(function () {
                    $list.removeClass('animated fadeOutDown speed-5x').hide();
                });

                $btn.removeClass('active');

                $btn.find('.addIcon').show();
                $btn.find('.closeIcon').hide();
                if (goBack) {
                    //ncmHotKeys.build('uiReset');
                    ncmSettings.setDefaultModuleView('load');
                }
                callback && callback();
            } else {
                $btn.removeClass('active');
                $btn.find('.addIcon').show();
                $btn.find('.closeIcon').hide();
                if (goBack) {
                    //ncmHotKeys.build('uiReset');
                    ncmSettings.setDefaultModuleView('load');
                }
                callback && callback();
            }
        }
    }

    $('#modulesBtnMain').tooltip('hide');

    if (action == 'show') {
        showMods(callback);
    } else if (action == 'hide') {
        hideMods(false, callback);
    } else if (action == 'back') {
        backMods(callback);
    } else if (action == 'auto') {//auto detect
        if ($btn.hasClass('active')) {
            hideMods(true, callback);
        } else {
            showMods(callback);
        }
    } else if (action == 'load') {



    } else {
        callback && callback();
    }
}

var moduleWrapElement = function () {
    var ncmDebtAlert = '';

    if (ncmHelpers.valid(ncmGlobals, 'settings')) {
        if (ncmHelpers.valid(ncmGlobals.settings[0], 'accountBlockingAlert')) {
            if (ncmGlobals.settings[0].accountBlockingAlert.is == 1) {
                ncmDebtAlert = '<div class="col-xs-12 text-center wrapper bg-danger lt font-bold text-u-c">' + ncmGlobals.settings[0].accountBlockingAlert.txt + '</div>';
            }
        }
    }

    var leWrap = ncmDebtAlert + '<section id="moduleWrap" class="col-xs-12 no-padder clear"></div>';
    if (!$('section#moduleWrap').length) {
        if (isMobile.phone) {
            $('#modalHotkeys .imodal-body div#modalHotkeysBody').html(leWrap);
        } else {
            $('#hotkeys').html(leWrap);
        }
    }
    return $('section#moduleWrap');
};

var ncmSpaces = {
    userToSpace: false,
    action: (action, callback) => {
        if (action == 'show') {
            var url = masterUrl + 'load?l=' + ncmHttp.masterUrlParams({ load: 'tables' });
            var $container = moduleWrapElement();

            if (isMobile.phone) {
                imodaler({
                    element: $('#modalHotkeys'),
                    onBefore: function () {
                        if (!$('#itsTable1').length) {//solo muestro placeholder cuando no estoy en modo tables
                            ncmUIX.setLoadingPlaceHolder({ el: $container, lg: 'bg_tables.png', xs: 'bg_tables_xs.png' });
                        }
                    }
                });
            } else {
                if (!$('#itsTable1').length) {//solo muestro placeholder cuando no estoy en modo tables
                    ncmUIX.setLoadingPlaceHolder({ el: $container, lg: 'bg_tables.png', xs: 'bg_tables_xs.png' });
                }
            }

            ncmSpaces.view($container, callback);

        } else if (action == 'hide') {

            if (!isMobile.phone) {
                ncmHotKeys.build(function () {
                    callback && callback();
                });
            }
        }
    },
    view: ($container, callback) => {

        var url = masterUrl + 'load?l=' + ncmHttp.masterUrlParams({ load: 'tablesJson' });
        ncmHttp.getit(url, function (data) {
            ncmSpaces.cache = data;
            var grid = ncmSpaces.builder();
            $container.html(grid, () => {
                $.each(data.table, function (table, values) {
                    var $table = '#itsTable' + table;
                    var bgColor = 'bg-success text-white';

                    $($table + ' .tableOpsBtn').toggleClass('hidden');
                    $($table + ' .tableNo').addClass('text-white');
                    $($table + ' .tableNo').attr('data-type', 'addOrder');

                    if (values.orders < 1) {
                        $($table).find('[data-type="ordersList"]').addClass('disabled');
                    }

                    if (!values.editable) {
                        $($table).find('[data-type="ordersList"]').addClass('disabled').attr('disabled', 'disabled');
                        $($table).find('[data-type="renameTable"]').addClass('disabled').attr('disabled', 'disabled');
                        $($table).find('[data-type="closeTable"]').addClass('disabled').attr('disabled', 'disabled');
                    }

                    if (values.joined) {
                        var totalTables = iftn(ncmGlobals.settings[0].tablesCount, 100);

                        // Verifico primero que la mesa que ha sido unida sea una mesa valida
                        if (parseInt(values.joined) > parseInt(totalTables)) {
                            // Si no es una mesa valida, paso la mesa unida a cero 
                            values.joined = 0;
                        } else {
                            $($table + ' div.tableNo div.h1').text(table + '/' + values.joined);
                            $($table + ' [data-html="#tablesActionSheet' + table + '"]').attr("data-html", "#tablesActionSheet" + values.joined);
                            $($table + ' [data-position="' + table + '"]').attr("data-position", values.joined);
                            $('#tablesActionSheet' + table + ' .spaceName').text("Espacio " + table + '/' + values.joined);
                        }
                    }

                    if (values.status == 2) {//reservado
                        bgColor = 'bg-warning lt text-white';
                    }

                    $($table + ' .tableBg').removeClass('bg-light').addClass(bgColor);

                    if (values.note) {
                        // $($table + ' .tableOpsNote').text(values.note);
                        $($table + ' .tableStatus').text(values.note);
                    }

                    var uname = 'Sin Asignar';

                    if (values.userId) {
                        var uindex = arraySearch(ncmGlobals.users, 'userId', values.userId);
                        if (uindex > -1) {
                            uname = ncmGlobals.users[uindex].name;
                        }
                    }

                    // $($table + ' .tableStatus').text(uname);
                    $($table + ' .tableOpsNote').text(uname);

                });

                callback && callback();
            });
        }, false, false, 'json');
    },
    builder: () => {

        var totalTables = parseInt(iftn(ncmGlobals.settings[0].tablesCount, 100)) + 1;
        var t = 0;
        var row = [];
        var ro = '';

        while (t < totalTables) {

            if (t == 0) {

                ro = '<div class="col-sm-2 col-xs-6 wrapper-xs" id="itsTable' + t + '">' +
                    '   <div class="col-xs-12 bg-light no-padder r-3x tableBg">' +
                    '       <div class="clear" style="min-height:32px!important;">' +
                    '       </div>' +
                    '       <div class="clickeable text-center" data-kind="addCustomTable" data-type="openTable" data-position="' + t + '" >' +
                    '           <div class="h1 no-padder font-bold"> <i class="material-icons text-dark md-36">add</i> </div>' +
                    '           <div class="text-sm m-b tableStatus text-ellipsis">Espacio</div>' +
                    '       </div>' +
                    '   </div>' +
                    '</div>';

            } else {

                ro = '<div class="col-sm-2 col-xs-6 wrapper-xs" id="itsTable' + t + '">' +
                    '   <div class="col-xs-12 bg-light no-padder r-3x tableBg">' +
                    '       <div class="clear tableOps">' +

                    '           <div class="col-xs-9 no-padder">' +

                    '           <a href="#" class="wrapper-xs btn clickeable pull-left tableOpsBtn" data-type="tableReservation" data-position="' + t + '" data-toggle="tooltip" data-original-title="Reservar Espacio" data-placement="bottom">' +
                    '               <i class="material-icons md-18 text-muted">timer</i>' +
                    '           </a>' +

                    '           <span class="pull-left text-center wrap-t-xs wrap-l-xs tableOpsNote" style="min-height:32px!important;">  </span>' +

                    '           </div>' +
                    '           <div class="col-xs-3 no-padder">' +

                    '           <a href="#" class="wrapper-xs hidden btn clickeable pull-right hide-basic tableOpsBtn" data-type="actionSheet" data-html="#tablesActionSheet' + t + '">' +
                    '               <i class="material-icons text-white">more_vert</i>' +
                    '           </a>' +

                    '           </div>' +

                    '       </div>' +
                    '       <div class="clickeable text-center tableNo" data-kind="table" data-type="openTable" data-position="' + t + '" >' +
                    '           <div class="h1 no-padder font-bold">' + t + '</div>' +
                    '           <div class="text-sm m-b tableStatus text-ellipsis">Libre</div>' +
                    '       </div>' +
                    '   </div>' +
                    '</div>';

                ro += '<span id="tablesActionSheet' + t + '" class="hidden">' +
                    '   <div class="text-center m-b"><h3 class="font-bold spaceName m-n">Espacio ' + t + '</h3></div>' +
                    '   <a href="#viewTable&t=' + t + '" class="wrapper text-md block navigate">' +
                    '       <i class="material-icons text-muted m-r">receipt</i>Ver detalle' +
                    '   </a>' +
                    '   <a href="#" class="clickeable wrapper text-md block" data-type="renameTable" data-position="' + t + '">' +
                    '       <i class="material-icons text-muted m-r">chat_bubble_outline</i>Renombrar' +
                    '   </a>' +
                    '   <a href="#" class="clickeable wrapper text-md block" data-type="joinSpaces" data-position="' + t + '">' +
                    '       <i class="material-icons text-muted m-r">close_fullscreen</i>Unir espacios' +
                    '   </a>' +
                    '   <a href="#" class="clickeable wrapper text-md block" data-type="moveOrders" data-position="' + t + '">' +
                    '       <i class="material-icons text-muted m-r">input</i>Cambiar de espacio' +
                    '   </a>' +
                    '   <a href="#" class="clickeable wrapper text-md block" data-type="asignUserToSpace" data-position="' + t + '">' +
                    '       <i class="material-icons text-muted m-r">person</i>Asignar Usuario' +
                    '   </a>' +
                    '   <a href="#" class="clickeable wrapper text-md block navigate hidden" data-type="processAndDivide" data-position="' + t + '" data-kind="table">' +
                    '       <i class="material-icons text-muted m-r">shopping_basket</i>Dividir en cuentas iguales' +
                    '   </a>' +
                    '   <a href="#" class="clickeable wrapper text-md block" data-type="closeTable" data-position="' + t + '" data-kind="table">' +
                    '       <i class="material-icons text-danger m-r">close</i>Cerrar espacio' +
                    '   </a>' +
                    '</span>';

            }

            row.push(ro);

            t++;
        }

        return row.join('');
    },
    cache: {}
};



var ncmMaths = {
    parseFloatSafe: function (num, qty) {
        qty = iftn(qty, 2);
        if (ncmHelpers.validity(num)) {
            var ret = parseFloat(num.toString().replace(/,/g, '.'));
            return parseFloat(ret.toFixed(qty));
        } else {
            return 0;
        }
    },
    // Esta función sirve para obtener un monto con decimales sin redondear para arriba el monto, ej: 31666.666666666668 ---> 31666.66
    twoDecimalsWithoutRounding(n) {
        let t = n.toString();
        let regex = /(\d*.\d{0,2})/;
        return t.match(regex)[0];
    },
    getRandomInt: function (min, max) {
        min = Math.ceil(min);
        max = Math.floor(max);
        return Math.floor(Math.random() * (max - min + 1)) + min;
    },
    formatNumber: (options) => {

        options.thousandSeparator = iftn(options.thousandSeparator, ncmGlobals.settings[0].thousandSeparator);
        options.decimal = iftn(options.decimal, ncmGlobals.settings[0].decimal);

        if (ncmGlobals.currency) {
            options.decimal = 'yes';
        }

        var comma = ',',
            dot = '.',
            number = options.number,
            dN = 0,
            dS = dot,
            tS = comma,
            currency = iftn(options.currency, '', ncmMaths.setCurrency('symbol'));

        if (options.decimal == 'yes') {
            dN = iftn(options.customDecimal, 2);
        } else if (options.decimal == 'auto') {
            if (ncmMaths.isFloat(number)) {
                dN = iftn(options.customDecimal, 2);
            } else {
                dN = 0;
                //number = parseInt(number);
                number = Math.round(number);
            }
        } else {//si no usa decimales hago integer
            //number = parseInt(number);
            number = Math.round(number);
        }

        if (options.max > 0) {
            number = (number > options.max) ? options.max : number;
        }

        if (options.decimal == 'yes' && options.typing) {
            number = ncmMaths.typeInDecimalMaker(number, dN);
        }

        if (options.thousandSeparator != 'comma') {
            dS = comma;
            tS = dot;
        }

        if (options.raw) {
            return ncmMaths.typeInDecimalMaker(options.number, dN);
        } else {
            var num = $.number(number, dN, dS, tS);
            return currency + num;
        }
    },
    setCurrency: function (amount, inverted) {
        if (amount === 'symbol') {
            return ncmHelpers.valid(ncmGlobals, 'currency') ? ncmGlobals.currency : ncmHelpers.valid(ncmGlobals.settings[0], 'currency');
        }

        var currCur = ncmGlobals.currency;
        if (currCur && amount > 0) {
            if (ncmHelpers.valid(ncmGlobals.settings[0].fullSettings, 'currencies')) {
                var currencies = ncmGlobals.settings[0].fullSettings.currencies;
                var rate = inArrayKeySearch(currCur, currencies);
                if (rate > 0) {
                    if (rate && rate > 0) {
                        if (inverted) {
                            amount = ncmMaths.divider(amount, rate, true);
                        } else {
                            amount = Math.round(((amount * rate) + Number.EPSILON) * 100) / 100;//Math.round( amount * rate );
                        }
                    }
                }
            }
        }

        return amount;
    },
    typeInDecimalMaker: function (number, dN) {
        //Convierto en string de Int
        var strnumber = number.toString();
        strnumber = explodes(strnumber, '.', '');
        strnumber = explodes(strnumber, ',', '');
        //
        if (!ncmHelpers.valid(dN)) {
            //number = parseInt(number);
            number = Math.round(number);
            return number;//si no hay decimales devuelvo un entero
        }

        dN = iftn(dN, 2);
        var n = '';
        var count = (dN - (strnumber.length - 1));

        for (var u = 0; u < count; u++) {//genero los ceros necesarios para completar la cantidad de decimales requeridos
            n += '0';
        }

        number = n + strnumber;
        var part = number.split('');
        var n = '';

        for (var i = 0; i < part.length; i++) { //inserto el punto decimal donde corresponde
            if (i == (part.length - dN)) {
                n += '.';
            }
            n += part[i];
        }

        number = n;
        return $.number(number, dN, '.', '');
    },
    cleanNumbers: function (number) {
        //no se permiten mas de 1 %,',' y -, secuencias seguidas, finalizar con ,.-

        number = number.replace(',,', ",");
        number = number.replace('..', ".");
        number = number.replace('--', "-");
        number = number.replace('%%', "%");

        return number;
    },
    leadingZerosFn: function (num, size) {
        var s = num + "";
        while (s.length < size) s = "0" + s;
        return s;
    },
    getTaxOfPrice: function (tax, price) {
        //thalog('getTaxOfPrice fn');
        var out = 0;

        if (tax && price && tax > 0) {
            var taxVal = price / (1 + (tax / 100));
            var total = price - taxVal;

            if (total && total > 0) {
                out = total;
            } else {
                out = 0;
            }
        } else {
            out = price;
        }

        return out;
    },
    addTaxToPrice: function (per, price) {
        if (!per || !price) {
            return 0;
        }

        per = ncmMaths.parseFloatSafe(per);
        price = ncmMaths.parseFloatSafe(price);
        var res = (price * (per / 100));

        return res;
    },
    decimalSetter: function (number, decimal, thousandSeparator) {
        if (decimal == 'yes') {
            if (thousandSeparator == 'dot') {
                return number.replace(".", ",");
            } else {
                return number;
            }
        } else {
            return number;
        }
    },
    removeTax: function (tax, price) {
        if (tax > 0) {
            var priceLess = price / (1 + (tax / 100));
            return ncmMaths.parseFloatSafe(priceLess);
        }
    },
    addDiscount: function (discount, price) {
        thalog('addDiscount fn');
        if (discount && price) {
            var total = Math.abs((price * discount) / 100);
            if (total && total > 0) {
                return total;
            } else {
                return 0;
            }
        } else {
            return 0;
        }
    },
    isNumber: function (n) {
        return !isNaN(parseFloat(n)) && isFinite(n);
    },
    isInt: function (n) {
        return Number(n) === n && n % 1 === 0;
    },
    isFloat: function (n) {
        return Number(n) === n && n % 1 !== 0;
    },
    resta: function (a, b, force, noNegative) {
        var out = 0;
        if (force) {
            out = a - b;
        } else {
            if (a > b) {
                out = a - b;
            } else if (b > a) {
                out = b - a;
            } else {
                out = 0;
            }
        }

        if (noNegative) {
            if (out < 0) {
                out = 0;
            }
        }

        return out;
    },
    divider: function (a, b, force) {
        if (a == 0 || b == 0) {//avoid division by 0
            return 0;
        }

        if (force) {
            return a / b;
        }

        if (a > b) {
            return a / b;
        } else if (b > a) {
            return b / a;
        } else {
            return a;
        }
    },
    rule3Simple: function (percent, total) {
        return ncmMaths.resta(total, ncmMaths.divider(percent * total, 100, true));
    },
    findPercentOfTotal: function (amount, total) {
        var divide = ncmMaths.divider(amount, total, true);
        return divide * 100;
    }
};

function selectRegisterById(registerId) {
    // Usamos la función find para buscar la caja por su registerId
    const registroSeleccionado = ncmGlobals.registers.find(registro => registro.registerId === registerId);

    // Si encontramos el registro, lo devolvemos; de lo contrario, devolvemos null
    return registroSeleccionado || null;
}


var ncmFE = {
    py: {
        build: () => {

            var register = selectRegisterById(window.appConfigObj[0].registerId);
            if (ncmHelpers.valid(ncmGlobals.settings[0].modules, 'electronicInvoice')) {
                if (!ncmHelpers.valid(ncmGlobals.settings[0].modules.electronicInvoice, 'status')) {
                    return false;
                } else {
                    if (register) {
                        if (!register.electronicInvoice == "1") {
                            return false;
                        }
                    } else {
                        return false;
                    }
                }
            } else {
                return false;
            }

            // Evitamos que se envie a factura electronica una venta o devolucion interna
            if (ncmTransactions.saleInternal || ncmTransactions.returnSaleTags) {
                ncmTransactions.returnSaleTags = false;
                return false;
            }

            //CUSTOMER
            var customerData = '';
            var docNo = 'XXXX';
            var dv = '';
            var isRUC = false;
            var tipCont = null;

            if (ncmHelpers.valid(ncmTransactions, 'customer')) {
                customerData = ncmTransactions.customer;
                customerData.name = customerData.name ? customerData.name : customerData.fullName;

                if (ncmHelpers.validInObject(customerData, 'ruc')) {

                    if (customerData.ruc.includes('-')) {
                        isRUC = true;
                        docNo = customerData.ruc.split('-')[0];
                        dv = customerData.ruc.split('-')[1];

                        if (docNo.startsWith('8') && docNo.length >= 8) {
                            tipCont = 2;
                        }

                    } else {
                        docNo = customerData.ruc ? customerData.ruc : customerData.ci;
                    }

                }
            }
            //timbrado
            var thisDoc = ncmTransactions.cDocData();
            var leadingZeros = ncmTransactions.cRegisterData().leadingZero;
            var thisRegister = ncmTransactions.cRegisterData();
            var invoiceNum = ncmMaths.leadingZerosFn(thisDoc.invoiceNo, leadingZeros);
            var curOutlet = ncmTransactions.cOutletData();
            var authNo = thisRegister.invoiceAuthNo;
            var establecimiento = thisRegister.invoicePrefix.split('-')[0];
            var puntoExpedicion = thisRegister.invoicePrefix.split('-')[1];
            var fecIni = thisRegister.invoiceAuthStart + "T00:00:00-04:00";

            //payments
            var payments = [];

            var saleCondition = 1; //contado
            var operacionCreditoTipo = null;
            var plazoCredito = null;
            var notaCreditoDebito = null;
            var docAsociados = null;
            var fecha = getFullDateAndTime();
            if (ncmTransactions.finalType() == 3) { //credito
                saleCondition = 2;
                operacionCreditoTipo = 1;

                // Obtener la fecha proporcionada desde la variable window.dueDate
                var fechaProporcionadaStr = window.dueDate; // Asumiendo que esto contiene la fecha en formato "2023-10-20 12:00:00"

                // Convertir la fecha proporcionada en un objeto Date
                var fechaProporcionada = new Date(fechaProporcionadaStr.replace(/-/g, "/"));

                // Obtener la fecha actual
                var fechaActual = new Date();

                // Calcular la diferencia en milisegundos
                var diferenciaEnMilisegundos = fechaProporcionada - fechaActual;

                // Calcular la diferencia en días
                var diasDiferencia = diferenciaEnMilisegundos / (1000 * 60 * 60 * 24);

                // Redondear el valor de diasDiferencia
                var diasRedondeados = Math.round(diasDiferencia);

                // Crear una cadena con la cantidad de días y la palabra "días"
                var cadenaDias = diasRedondeados.toString() + ' días';

                plazoCredito = cadenaDias;

            } else if (ncmTransactions.finalType() == 6) { // devolucion (Nota de Credito) 
                invoiceNum = ncmMaths.leadingZerosFn(thisDoc.returnNo, leadingZeros);
                // 1= Devolución y Ajuste de precios 2= Devolución 3= Descuento 4= Bonificación 5= Crédito incobrable 6= Recupero de costo 7= Recupero de gasto 8= Ajuste de precio
                notaCreditoDebito = {
                    "motivoEmision": 1
                };

                // tipo: 1 Electronico, 2 Impreso, 3 Constancia Electrónica
                // tipoDocAsociado: 1 Factura, 3 Nota de Débito, 4 Nota de Remisión
                docAsociados = [
                    {
                        "tipo": 1,
                        "cdc": !!ncmTransactions.cdc ? ncmTransactions.cdc : "",
                        "tipoDocAsociado": "1"
                    }
                ];

                saleCondition = null;
                fecha = !!ncmTransactions.saleDate ? ncmTransactions.saleDate : fecha;

                authNo = thisRegister.returnAuthNo;
                establecimiento = thisRegister.returnPrefix.split('-')[0];
                puntoExpedicion = thisRegister.returnPrefix.split('-')[1];
                fecIni = iftn(thisRegister.returnAuthStart) + "T00:00:00-04:00";

            } else if (ncmTransactions.finalType() == 0) { //contado
                if (!ncmHelpers.valid(window.paymentsObj)) {
                    payments = [
                        {
                            "tipoPagoCodigo": 1,
                            "monto": ncmTransactions.updatePrice('total')
                        }
                    ];
                } else {
                    $.each(window.paymentsObj, function (i, val) {
                        var cod = 1;//cash
                        var obj = {
                            "tipoPagoCodigo": cod,
                            "monto": val.price
                        };

                        if ($.inArray(val.type, ['creditcard', 'debitcard']) > -1) {
                            cod = 4;
                            obj = {
                                "tipoPagoCodigo": cod,
                                "monto": val.price,
                                "tarjeta": {
                                    "denominacionTarjeta": 99,
                                    "formaProcesamiento": 1
                                }
                            };


                        }

                        if ($.inArray(val.type, ['ePOSCard', 'ePOS']) > -1) {
                            cod = 21;
                            obj = {
                                "tipoPagoCodigo": cod,
                                "monto": val.price,
                                "tarjeta": {
                                    "denominacionTarjeta": 99,
                                    "formaProcesamiento": 2
                                }
                            };


                        }

                        payments.push(obj);
                    });

                }
            }
            //

            //items
            var items = [];
            $.each(window.itemsObj, function (i, val) {

                if (val.price > 0) {

                    var afectTributaria = (val.tax > 0) ? 1 : 3; //si el iva es Cero la afectación es 3 (exento) sino es 1(gravIVA)
                    var propIva = (val.tax > 0) ? 100 : 0; //si el iva es Cero la proporcíon de iva es 0 (exento) sino es 100(gravIVA)

                    items.push({
                        "itemCodigo": val.uId ? val.uId : val.itemId,
                        "itemDescripcion": val.name,
                        "cantidad": val.count,
                        "precioUnitario": val.price,
                        "afectacionTributaria": afectTributaria,
                        "proporcionIVA": propIva,
                        "tasaIVA": val.tax > 0 ? val.tax : 0
                    });

                }
            });

            var obj = {
                "timbrado": authNo,
                "establecimiento": establecimiento,
                "puntoExpedicion": puntoExpedicion,
                "documentoNro": invoiceNum,
                "fecIni": fecIni,
                "sucursal": curOutlet.name,
                "operacionMoneda": "PYG",
                "docNro": docNo,
                "dv": dv,
                "razonSocial": customerData.name,
                "tipoContribuyente": tipCont,
                "direccion": (!!customerData.address ? customerData.address : ""),
                "email": (!!customerData.email ? customerData.email : ""),
                "telefono": (!!customerData.phone ? customerData.phone : ""),
                "fecha": fecha,
                "condicion": saleCondition,
                "operacionTipo": operacionCreditoTipo,
                "plazoCredito": plazoCredito,
                "tiposPagos": payments.length !== 0 ? payments : null,
                "detalles": items,
                "totalComprobante": ncmTransactions.updatePrice('total'),
                "notaCreditoDebito": notaCreditoDebito,
                "docAsociados": docAsociados
            };
            return obj;
        }
    }
};

