                        $.each(window.itemsObj, function (i, item) {
                            item.count = ncmMaths.parseFloatSafe(item.count + (item.countCopy * toDivide) - (item.count * toDivide));
                            item.oQty = ncmMaths.parseFloatSafe(item.oQty + (item.oQtyCopy * toDivide) - (item.oQty * toDivide));
                            item.total = ncmMaths.twoDecimalsWithoutRounding(item.totalCopy);
                            item.price = ncmMaths.twoDecimalsWithoutRounding(item.priceCopy);
                            item.uniPrice = ncmMaths.twoDecimalsWithoutRounding(item.uniPriceCopy);
                        });

