                            var url = masterUrl + 'action?l=' + ncmHttp.masterUrlParams({ action: 'sale', status: id, s: 6, schedule: true, uid: orgTrsID });
                            ncmHttp.getit(url, function () {
                                $('.imodal').imodal('hide');
                            });
