var ncmDialogs = {
    alert: function (msg, message, type) {
        var icon = 'warning';
        var title = msg;

        if (type == 'error' || type == 'danger') {
            icon = 'error';
            title = 'Error';
            message = msg;
        } else {

        }

        Swal.fire({
            title: title,
            text: message,
            type: icon,
            confirmButtonText: 'Aceptar'
        });
    },
    confirm: function (title, msg, type, callback, btns) {
        btns = btns ? btns : {};
        type = (type == 'danger') ? 'error' : type;
        Swal.fire({
            title: title,
            text: msg,
            type: type,
            showCancelButton: true,
            confirmButtonText: ('accept' in btns) ? btns.accept : 'Aceptar',
            cancelButtonText: ('cancel' in btns) ? btns.cancel : 'Cancelar',
            willOpen: function () {
                $('.swal2-content').css({ 'font-weight': 'normal' });
            }
        }).then((result) => {
            if (result.value) {
                callback && callback(result.value);
            } else if (result.dismiss === Swal.DismissReason.cancel) {
                callback && callback(false);
            } else {
                callback && callback(false);
            }
        }, (dismiss) => {
            callback && callback(false);
        });
    },
    prompt: function (title, val, type, callback) {
        ncmUIX.setDarkMode();
        Swal.fire({
            title: title,
            input: (!type ? 'text' : type),
            inputValue: val ? val : '',
            showCancelButton: true,
            confirmButtonText: 'Aceptar',
            cancelButtonText: 'Cancelar',
            inputPlaceholder: title,
            willOpen: function () {
                ncmUIX.setDarkMode();
            },
            onOpen: function () {
                $('.swal2-input').focus();
                onClickWrap('.swal2-input', function (event, tis) {
                    tis.focus();
                }, false, true);
            },
            inputValidator: (value) => {
                if (!value) {
                    return 'No puede dejar el campo en blanco'
                }
            }
        }).then((result) => {
            if (result.value) {
                callback && callback(result.value);
            } else if (result.dismiss === Swal.DismissReason.cancel) {
                callback && callback(false);
            }
        })
    },
    toast: function (message, type, duration) {
        ncmUIX.setDarkMode();
        type = (type == 'danger') ? 'error' : type;
        var tost = Swal.mixin({
            toast: true,
            position: 'top-left',
            showConfirmButton: false,
            timer: iftn(duration, 3000),
            timerProgressBar: true,
            willOpen: function () {
                ncmUIX.setDarkMode();
            },
            onOpen: (toast) => {
                toast.addEventListener('mouseenter', Swal.stopTimer)
                toast.addEventListener('mouseleave', Swal.resumeTimer)
            }
        });

        tost.fire({
            type: type,
            title: message
        });
    },
    push: (title, msg, url) => {
        var msg = msg ? msg : title;
        Push.create(title, {
            body: msg,
            icon: '/images/iconincomesm.png',
            timeout: 4000,
            onClick: () => {
                window.location = url;
            }
        });
        //return OneSignal.sendSelfNotification(title,msg,'/' + url,'/images/iconincomesm.png',false,false);
    }
};
