var conectivityAlertsManager = function (status, check) {
    var $div = $(".connectionStatus i");
    var $offlineMessage = $(".offlineMessage");
    if (status) {
        if (ncmHelpers.validity(check)) {
            $div.removeClass('text-danger text-warning text-success').addClass('text-success').text('signal_wifi_4_bar');
            $offlineMessage.addClass('hidden'); // Ocultar el mensaje de desconexión
        }
    } else {
        if (ncmHelpers.validity(check)) {
            $div.removeClass('text-danger text-warning text-success').addClass('text-danger').text('signal_wifi_off');
            $offlineMessage.removeClass('hidden');// Mostrar el mensaje de desconexión
        }
    }
};

var checkInternet = function (callback) {
    //thalog('checkInternet fn');
    if (window.isUserActive) {
        Offline.check();
        if (Offline.state == "up") {
            window.isServerOnline = true;
            conectivityAlertsManager(true, true);
            return true;
        } else if (Offline.state == "down") {
            window.isServerOnline = false;
            conectivityAlertsManager(false, true);
            return false;
        }
    }
};

var checkAppVersion = function () {
    var version = ncmGlobals.settings[0].webAppVersion;
    var versions = explodes(version, '.', '');
    var currentraw = $('.appVersionCachedInHTML:first').text();
    var current = explodes(currentraw, '.', '');
    var isMac = navigator.platform.indexOf('Mac') > -1;
    var steps = "presione las teclas " + ((isMac) ? '⌘+SHIFT+R' : 'CTRL+F5') + " para actualizar.";
    if (isMobile.any) {
        steps = "cierre y vuelva a abrir la aplicación para actualizar.";
    }

    if (versions > current) {
        ncmAlerts.alert({
            title: "Nueva versión disponible. (" + version + ")",
            body: "Para un correcto funcionamiento actualice su caja (" + currentraw + "), " + steps
        }, (result) => {
            if (result) {
                splashManager('show', false, true);
                window.appConfigObj[0].lastTimeUpdate = false;
                ncmStorage.addEntry('appConfig', appConfigObj);
                updateDB.all(function () {
                    splashManager('hide', false, true);
                    location.reload(true);
                }, false, false, false);
            }
        });
    }

    return {
        "version": version,
        "versions": versions,
        "currentraw": currentraw,
        "current": current
    };
};


