//UI
var splashManager = function (action, callback, forceWebMode) {
    if (action == 'hide') {

        pluginExecute('splashscreen', function () {
            navigator.splashscreen.hide();
            $('#splash').hide();
            callback && callback();
        }, function () {

            setTimeout(function () {
                $('#loadingBarHolder').addClass('bounceOutDown');

                if ($('#loadingBar').hasClass('bg-dark') || $('#loadingBar').hasClass('bg-white')) {
                    $('#loadingBar').removeClass('bg-dark bg-white').addClass('bg-success');
                }

                setTimeout(function () {
                    $('#splash').addClass('fadeOut speed-4x').afterAnimation(function () {
                        $('#splash').removeClass('fadeIn fadeOut pulse infinite');
                        $('#loadingBarHolder').removeClass('bounceOutDown');
                        $('#loadingBar').css('width', '0px');
                        $('#splash').hide();
                        callback && callback();
                    });
                }, 500);
            }, 500);

        }, false, forceWebMode);

    } else {
        pluginExecute('splashscreen', function () {
            navigator.splashscreen.show();
        }, function () {
            $('#splash').removeClass('fadeOut fadeIn').show();
        }, false, forceWebMode);
    }
};

var welcomeMessage = function () {
    var myDate = new Date();

    /* hour is before noon */
    if (myDate.getHours() < 12) {
        return 'Buenos días';
    } else if (myDate.getHours() >= 12 && myDate.getHours() <= 18) { /* Hour is from noon to 5pm (actually to 5:59 pm) */
        return 'Buenas tardes';
    } else if (myDate.getHours() > 18 && myDate.getHours() <= 24) { /* the hour is after 5pm, so it is between 6pm and midnight */
        return 'Buenas noches';
    } else { /* the hour is not between 0 and 24, so something is wrong */
        return 'Hola';
    }
};

