var loadToolTip = function (ops, exept, el) {
    thalog('loadToolTip fn');

    var el = iftn(el, '[data-toggle="tooltip"]');
    var $el = $(el);
    ops = (ops) ? ops : {};
    ops.html = true;

    $('.tooltip.in').remove();

    $el.each(function () {
        var tis = $(this);

        if (!tis.length || tis.data('bs.tooltip')) {
            return;
        }

        if (ops.showOnly) {
            tis.tooltip('destroy').tooltip(ops).tooltip('show');
            return;
        } else if (ops.hideOnly) {
            tis.tooltip('destroy');
            return;
        }

        if (isMobile.any && !exept) {
            tis.tooltip('destroy').removeAttr('data-toggle');
        } else {
            tis.tooltip('destroy').tooltip(ops);//hace que sea mas lento
        }
    });
};

var smSc = function (height, sm, md, lg) {
    var out;
    if (height <= 760) {
        out = sm;
    } else if (height > 760 && height < 1024) {
        out = md;
    } else {
        out = lg;
    }

    thalog('window height: ' + height + ' out: ' + out);
    return out;
};

var hkSquaresToScreen = function () {
    thalog('hkSquaresToScreen fn');
    var h = $('#register').height();
    //var w         = $(window).width()-$('#sidebar').width();
    var cols = 50;
    var rows = smSc(h, 6, 7, 7); //cuantos rows aparecen visibles en el HK view, height sm, md, lg
    var amount = cols * rows;

    var out = [cols, rows, amount, hkSquareHeight(h, rows, 10)]; // cols,rows,num of squares, square height

    thalog(out);

    return out;

};

var hkSquareHeight = function (wHeight, rows, paddingTotal) {
    h = (wHeight - 20);

    return (h / rows) - paddingTotal;
};

var getFirstLetters = function (text) {
    if (!text) {
        return '';
    }

    var out = '<span class="text-u-c">' + text.charAt(0) + '</span>' + text.charAt(1);
    return out;
};

