    adjustStrToTable(string, count, last) {
        var out = '';
        if (!ncmMaths.isNumber(string)) {
            var strToCount = string.replace(' ', '-');
        } else {
            var strToCount = string.toString().replace(' ', '-');
        }
        var strL = strToCount.length;
        if (strL > count) { //si el str tiene mas caracteres que lo permitido, elimino
            var toErase = strL - count;
            toErase = strL - toErase;
            out = string.substring(0, toErase);
        } else if (strL < count) { //si el str tienen menos de los permitido le anhado espacios en blanco
            var toAdd = count - strL;
            var spc = ' ';
            var ttlSpc = '';
            for (var i = 0; i < toAdd; i++) {
                ttlSpc += spc;
            }
            out = string + ttlSpc;
        } else {
            out = string;
        }

        if (last == true) {
            return out;
        } else {
            return out + '\t';
        }
    },
