var oneClickWrap = function (element, callback, propagate) { //este metodo solo listen por una vez

    if (jQuery.type(element) === 'string') {
        $element = $(element);
    } else {
        $element = element;
    }

    $element.off('click').one('click', function (event) {
        thalog('fn oneClickWrap ' + element);
        event.preventDefault();
        if (!ncmHelpers.validity(propagate)) {
            event.stopPropagation();
        }
        callback && callback(event, $(this));
    });
};

function parse_url(str, component) {
    // http://kevin.vanzonneveld.net

    var query, key = ['source', 'scheme', 'authority', 'userInfo', 'user', 'pass', 'host', 'port',
        'relative', 'path', 'directory', 'file', 'query', 'fragment'],
        ini = (this.php_js && this.php_js.ini) || {},
        mode = (ini['phpjs.parse_url.mode'] &&
            ini['phpjs.parse_url.mode'].local_value) || 'php',
        parser = {
            php: /^(?:([^:\/?#]+):)?(?:\/\/()(?:(?:()(?:([^:@]*):?([^:@]*))?@)?([^:\/?#]*)(?::(\d*))?))?()(?:(()(?:(?:[^?#\/]*\/)*)()(?:[^?#]*))(?:\?([^#]*))?(?:#(.*))?)/,
            strict: /^(?:([^:\/?#]+):)?(?:\/\/((?:(([^:@]*):?([^:@]*))?@)?([^:\/?#]*)(?::(\d*))?))?((((?:[^?#\/]*\/)*)([^?#]*))(?:\?([^#]*))?(?:#(.*))?)/,
            loose: /^(?:(?![^:@]+:[^:@\/]*@)([^:\/?#.]+):)?(?:\/\/\/?)?((?:(([^:@]*):?([^:@]*))?@)?([^:\/?#]*)(?::(\d*))?)(((\/(?:[^?#](?![^?#\/]*\.[^?#\/.]+(?:[?#]|$)))*\/?)?([^?#\/]*))(?:\?([^#]*))?(?:#(.*))?)/ // Added one optional slash to post-scheme to catch file:/// (should restrict this)
        };

    var m = parser[mode].exec(str),
        uri = {},
        i = 14;
    while (i--) {
        if (m[i]) {
            uri[key[i]] = m[i];
        }
    }

    if (component) {
        return uri[component.replace('PHP_URL_', '').toLowerCase()];
    }
    if (mode !== 'php') {
        var name = (ini['phpjs.parse_url.queryKey'] &&
            ini['phpjs.parse_url.queryKey'].local_value) || 'queryKey';
        parser = /(?:^|&)([^&=]*)=?([^&]*)/g;
        uri[name] = {};
        query = uri[key[12]] || '';
        query.replace(parser, function ($0, $1, $2) {
            if ($1) { uri[name][$1] = $2; }
        });
    }
    delete uri.source;
    return uri;
}

// generate a random number within a range (PHP's mt_rand JavaScript implementation)
function mt_rand(min, max) {

    min = (min) ? min : 100000000;
    max = (max) ? max : 9999999999;

    min = parseInt(min, 10);
    max = parseInt(max, 10);

    return Math.floor(Math.random() * (max - min + 1)) + min;
}

function time() {
    //return Math.floor(new Date().getTime() / 1000);
    //sacamos opcion de microtime porque causa timestamps duplicados en la db ya que pueden pasar 2 en el mismo segundo en distintas empresas
    return new Date().getTime();
}

function numuid() {
    //genera un id unico entre 19 y 14 caracteres de largo
    var ran = Math.random() * (19 - 14) + 14;
    ran = parseInt(ran.toString().replace(".", ""));
    return ran;
}

function getFormattedDate() {
    return moment().format('YYYY-MM-DD HH:mm:ss');
}

function htmlEntities(str) {
    return String(str).replace(/&/g, '&').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '"');
}

function atou(b64) {
    return decodeURIComponent(escape(atob(b64)));
}

function utoa(data) {
    return btoa(unescape(encodeURIComponent(data)));
}

function getFullDateAndTime(dateonly, houronly, fromInput) {
    var baseDate = undefined;

    if (ncmHelpers.validity(ncmTransactions.customDate, 'string')) {
        baseDate = ncmTransactions.customDate;
    }

    if (dateonly == true) {
        return moment(baseDate).format('YYYY-MM-DD');
    } else if (houronly == true) {
        return moment(baseDate).format('HH:mm:ss');
    } else if (fromInput) {
        var val = $(fromInput).val();
        return iftn(val, moment(baseDate).format('YYYY-MM-DD HH:mm:ss'));
    } else {
        return moment(baseDate).format('YYYY-MM-DD HH:mm:ss');
    }

}

