        ncmHelpers.onClickWrap('#manualLogin', function (event, tis) {
            $('#loginForm,#loginQR').toggle();
            ncmUIX.setLoginHeight();
        });

        ncmHelpers.onClickWrap('#QRLoginBtn', function (event, tis) {
            $('#loginForm,#loginQR').toggle();
            ncmUIX.setLoginHeight();
            ncmUIX.setLoginQR();
        });

        ncmHelpers.onClickWrap('a.QRLoginPanelIframeClick', function (event, tis) {
            ncmUIX.setLoginHeight();
            ncmUIX.setLoginQR();
        });

        ncmHelpers.click('#toLoginBtn', function (event, tis) {
            if (!isMobile.phone) {
                $('#loginQR,#welcome').toggle();
                ncmUIX.setLoginQR();
            } else {
                $('#welcome,#loginForm').toggle();
                ncmUIX.setLoginForm();
            }
            ncmUIX.setLoginHeight();
        });

        //2. envio form de login
        ncmHelpers.onClickWrap('#btn-login', function () {
            //$('#loginForm').submit();
            ncmUIX.btnIndicator({
                btn: $('#btn-login'),
                status: 'disable',
                disabledText: 'Procesando'
            });

            var phoneCode = $('#loginForm .selectedPhoneCode').is(':visible') ? $('#loginForm .selectedPhoneCode').data('country') : false;
            var email = $('#loginForm .loginEmail').val();
            var pass = $('#loginForm #lgPassword').val();

            if (ncmHelpers.validity(email) && ncmHelpers.validity(phoneCode) && $.isNumeric(email)) {
                try {
                    email = libphonenumber.parsePhoneNumber(email, phoneCode).formatInternational();
                    email = email.replace(/\s/g, '');
                } catch (error) {
                    email = '';
                }
            }

            ncmAuth.login(email, pass, function () {
                ncmUIX.btnIndicator({
                    btn: $('#btn-login'),
                    status: 'disable',
                    disabledText: 'Ingresando'
                });
            }, function () {
                ncmUIX.btnIndicator({
                    btn: $('#btn-login'),
                    enabledText: 'Ingresar'
                });
            });

        });

        //3. verifico y accedo
        $('#loginForm').off('submit').on('submit', function (e) {
            return false;
        });

        ncmEvents.a();

        //SIGNIN
        //1. cargo formulario de verificacion SMS
