var buildItemLine = function (value, fNops, type) {
    var val = ncmGlobals.products[value];

    if (!val || val.deleted) {
        return;
    }

    var cr = ' › ';
    var itemId = val.itemId;
    var name = val.name;
    fNops.number = val.price;
    var price = ncmMaths.formatNumber(fNops);
    var count = ncmMaths.parseFloatSafe(getInventoryValue(val.inventory, appConfigObj[0].outletId, "count"));
    var index = val.index;

    var sku = iftn(val.sku, '', cr + val.sku);
    var brand = iftn(val.brand, '', cr + val.brand);
    var category = iftn(val.category, '', cr + val.category);
    var trInventory = val.trackInventory;
    var discount = val.fixedDiscount;
    var children = val.children;
    var imgFlag = val.image;
    var kind = val.kind;

    var itmDuration = '';
    if (val.duration && val.duration > 0) {
        itmDuration = '<span class="badge bg-light lter font-normal">' + convertMinsToHrsMins(val.duration) + '</span>';
    }

    var datatype = 'itemFromList';
    var invTextColor = (count < 1) ? 'danger' : 'success';
    var inventory = '<span class="label text-xs bg-light lter text-' + invTextColor + ' hide-low">' + ncmMaths.formatNumber({ number: count, decimal: 'auto' }) + '</span>';
    var prevImag = '';
    var inCircle = getFirstLetters(name);
    var bgCircle = 'bg-light lter';
    var giftBg = '';
    if (kind == 'giftcard') {
        inCircle = '<i class="material-icons">&#xe8f6;</i>';
        bgCircle = iftn(val.sku, 'gradBgOrange', 'text-white');
        giftBg = iftn(val.sku, '', 'background:#' + val.sku + ';');
    } else if (kind == 'inCredit') {
        inCircle = '<i class="material-icons">input</i>';
        bgCircle = 'gradBgGray';
    } else if (kind == 'discount') {
        inCircle = '<span class="font-bold" style="margin-bottom:1px;">%</span>';
        bgCircle = 'gradBgYellow';
    }

    if (ncmHelpers.ifIstrue(imgFlag)) {
        circle = '<img src="' + imgPath(ncmGlobals.settings[0].companyId + '_' + itemId, '40', '40') + '" width="40" class="img-circle">';
        prevImag = 'previewImage';
    } else {
        var circle = '<div class="h4 m-t-sm font-bold">' + inCircle + '</div>';
    }

    if (ncmHelpers.validity(discount)) {
        discount = Math.abs(val.price * (discount / 100));
        discount = val.price - discount;
        fNops.number = discount;
        price = '<strike class="text-xs text-danger block">' + price + '</strike>' + ncmMaths.formatNumber(fNops);
    }

    if (ncmHelpers.validity(val.isParent)) {
        price = '';
        inCircle = '<i class="material-icons">flip_to_front</i>';
        bgCircle = 'dk';
    }

    if (val.type == 'combo' || !ncmHelpers.validity(trInventory) || ncmHelpers.validity(val.isParent)) {
        inventory = '';
    }


    var lineBorder = (ncmUIX.isDarkMode) ? 'b-dark' : '';

    if (type == 'tr') {
        var tempp = '<tr class="text-left ' + lineBorder + ' clickeable b-b pointer" data-type="' + datatype + '" data-id="' + itemId + '" data-position="' + index + '" data-imgFlag="' + imgFlag + '">' +
            '   <td> <div class="font-bold">' + inventory + ' ' + name + ' ' + itmDuration + '</div> </td>' +
            '   <td class="text-right font-bold"> ' + price + ' </td>' +
            '</tr>';
    } else {

        var tempp = '<div class="col-xs-12 pointer text-left wrapper b-b ' + lineBorder + ' clickeable" data-type="' + datatype + '" data-id="' + itemId + '" data-position="' + index + '" data-imgFlag="' + imgFlag + '">' +
            '   <a href="#" class="pull-left m-r-sm thumb-sm ' + bgCircle + ' rounded text-center clickeable height40px" data-type="itemInfo" data-id="' + itemId + '" style="' + giftBg + '">' +
            circle +
            '   </a>' +
            '   <span class="pull-left font-bold">' +
            inventory + ' ' + name + ' ' + itmDuration +
            '       <div class="text-muted text-xs font-normal m-t-xs">' +
            ((isMobile.phone) ? sku : sku + brand) + category +
            '       </div> ' +
            '   </span>' +
            '   <span class="pull-right m-t-xs text-md">' + price + '</span>' +
            '</div>';

    }

    return tempp;
};

var itemsSearchAutocomplete = function (onBefore, onAfter, onHidden) {
    thalog('itemsSearchAutocomplete fn');

    var fNops = {
        number: 0
    };

    var emptyResults = ncmUIX.notFoundMsg('No se encontraron artículos');
    var $input = $('#itemInputBarcode');
    var $resultWrap = $('#encAutoComplete');
    var $resultWrapMsg = $('#encAutoCompleteMsg');
    var $resultHolder = $('#encAutoCompleteHolder');
    var $modal = $('#modalSpotlight');
    var timeouter = (window.srcItemsArr.length > 10000) ? 400 : 0;
    var delay = false;

    ncmUIX.setPopupClass($modal.find('div.imodal-content'));

    imodaler({
        element: $modal,
        onBefore: function ($this) {

            if (isMobile.any) {
                $resultWrapMsg.removeClass('hidden');
            }

            triggerInputKeyEvent($input);

            $input.off('keyup').on('keyup', function () {
                var $tis = $(this);

                clearTimeout(delay);

                delay = setTimeout(function () {

                    var val = $tis.val();
                    var res = _ncmFilterSearch({ query: val, db: window.srcItemsArr, min: 2, field: 'value' });
                    var outArr = [];
                    var prnt = emptyResults;

                    if (val.length > 0) {
                        $resultWrap.removeClass('hidden');
                        if (isMobile.any) {
                            $resultWrapMsg.addClass('hidden');
                        }
                    } else {
                        $resultWrap.addClass('hidden');
                        if (isMobile.any) {
                            $resultWrapMsg.removeClass('hidden');
                        }
                    }

                    if (res && res.length > 0) {
                        $.each(res, function (k, value) {
                            var nLine = buildItemLine(value, fNops);
                            if (nLine) {
                                outArr.push(nLine);
                            }
                        });
                        prnt = outArr.join('');
                    } else {
                        prnt = emptyResults;
                    }

                    $resultHolder.html(prnt);

                    ncmEvents.a();

                }, timeouter);
            });

            onBefore && onBefore($this);
        },
        onAfter: function ($this) {
            focusIt($input);

            $modal.trigger('inc.imodal.shown');

            onAfter && onAfter($this);
        },
        onHidden: function ($this) {
            ncmEvents.unHashUrl();
            ncmTransactions.addAddOns = false;

            $modal.trigger('inc.imodal.hidden');
            onHidden && onHidden($this);
        }
    });
};

var customerMandatoryFields = function () {
    //{"razon":"1","tin":"1","name":"1","email":"1","phone":"1","address":"1","birthday":"1","phone2":"1","address2":"1"}
    var mandatory = ncmHelpers.getValidObjectStr(ncmHelpers.valid(ncmGlobals.settings[0], 'mandatoryContact', ''));
    var dangerClass = 'b-b b-danger animated shakeX';
    var out = true;
    var $allInpts = $('#crname, #crruc, #crfullname, #crci, #cremail, #crphone, #craddress, #crbirthday, #crphone2, #craddress2');

    $allInpts.removeClass('b b-danger animated shakeX');

    setTimeout(function () {
        $allInpts.removeClass('b b-danger animated shakeX');
    }, 1500);

    if (!ncmHelpers.valid(mandatory)) {
        return out;
    }

    if ('razon' in mandatory) {
        $el = $('#crname');
        if ($el.val().length < 1) {
            $el.addClass(dangerClass);
        }
    }

    if ('tin' in mandatory) {
        $el = $('#crruc');
        if ($el.val().length < 1) {
            $el.addClass(dangerClass);
            out = false;
        }
    }

    if ('ci' in mandatory) {
        $el = $('#crci');
        if ($el.val().length < 1) {
            $el.addClass(dangerClass);
            out = false;
        }
    }

    if ('name' in mandatory) {
        $el = $('#crfullname');
        if ($el.val().length < 1) {
            $el.addClass(dangerClass);
            out = false;
        }
    }

    if ('email' in mandatory) {
        $el = $('#cremail');
        if ($el.val().length < 1) {
            $el.addClass(dangerClass);
            out = false;
        }
    }

    if ('phone' in mandatory) {
        $el = $('#crphone');
        if ($el.val().length < 1) {
            $el.addClass(dangerClass);
            out = false;
        }
    }

    if ('address' in mandatory) {
        $el = $('#craddress');
        if ($el.val().length < 1) {
            $el.addClass(dangerClass);
            out = false;
        }
    }

    if ('birthday' in mandatory) {
        $el = $('#crbirthday');
        if ($el.val().length < 1) {
            $el.addClass(dangerClass);
            out = false;
        }
    }

    if ('phone2' in mandatory) {
        $el = $('#crphone2');
        if ($el.val().length < 1) {
            $el.addClass(dangerClass);
            out = false;
        }
    }

    if ('address2' in mandatory) {
        $el = $('#craddress2');
        if ($el.val().length < 1) {
            $el.addClass(dangerClass);
            out = false;
        }
    }

    return out;
};

