    recordsEdit: function (cId) {
        var array = [];
        $('.customerRecordValue').each(function (i, val) {
            var id = $(this).attr('id');
            var value = $(this).val();
            var editableVal = $(this).html();
            var progress = $('#progress' + id).val();
            if ($(this).hasClass('switch')) {
                var $checkbox = $(this).find('input');
                var isChecked = $checkbox.attr('checked') ? true : false;
                var value = (isChecked) ? $checkbox.val() : 0;

                //if(isChecked){
                array.push({ "id": id, "value": value, "progress": progress });
                //}
            } else if ($(this)[0].hasAttribute('contenteditable')) {
                if (editableVal) {
                    array.push({ "id": id, "value": editableVal, "progress": progress });
                }
            } else {
                if (value) {
                    array.push({ "id": id, "value": value, "progress": progress });
                }
            }
        });

        var data = { 'customerId': cId, 'data': array };
        var store = { 'updateCustomerRecord': data, 'uid': ncmHelpers.generateUid() };

        ncmHttp.saveDataLocally(store, function (yes) {
            if (yes) {
                $('.imodal').imodal('hide');
                ncmAlerts.toast('Guardado', 'success');
            }
        });
    },
    getGeo: function (success, fail) {

        $.geolocation.get(
            {
                success: (position) => {

                    ncmAuth.activeUser.lat = position.coords.latitude;
                    ncmAuth.activeUser.lng = position.coords.longitude;

                    if (!ncmAuth.activeUser.trackGPS) { //si no tiene habilitado el trackeo no guardo su ubicación
                        ncmAlerts.toast("Habilitar GPS tracking", "danger");
                        return false;
                    }

                    success && success();

                },

                error: () => {
                    ncmAlerts.toast("Sin conexión GPS", "danger");
                    fail && fail();
                }
            }
        );

    },
