var ncmComboItem = {
    totalOnHand: 0,
    totalNeeded: 0,
    maxim: [],
    itemsInCombo: [],
    preDefined: false,
    table: (index, itemId, callback) => {
        ncmComboItem.totalOnHand = 0;
        ncmComboItem.totalNeeded = 0;
        ncmComboItem.maxim = [];
        ncmComboItem.itemsInCombo = [];
        //var createComboTable
        //fromList      = (fromList)?'true':'false';
        var noContent = '<tr class="text-center"> <td colspan="3"> <i class="icon-layers block text-muted m-t-lg" style="font-size:60px;"></i> <br> <h4 class="m-n">Artículos</h4> </td> </tr>';
        var list = '<table class="table hover no-radius m-b-none no-bg m-t-n-xxs no-border no-padder comboList"></table>';
        $('.modifierDatatable').html(list);

        var row = '';
        var arr = ncmGlobals.products;
        var cr = ' › ';
        var length = arr.length;

        $('#comboModalComment').val('');

        if (length > 0 && ncmHelpers.validity(arr[index].compound)) {

            var combo = ncmHelpers.getValidObjectStr(arr[index].compound);
            var preSelected = ncmHelpers.valid(combo[0], 'select');
            var preSelectEx = [];

            $('#comboModalTitle').text(arr[index].name);

            var fNops = { number: 0 };

            $.each(combo, function (inde, val) {

                var catId = val["id"];

                if (val["units"] < 0 && !ncmComboItem.preDefined) {
                    //busco index de este irem
                    var predIndx = arraySearch(ncmGlobals.products, 'itemId', val["id"]);
                    // row += '<tr class="hidden" data-id="' + val["id"] + '" data-preselected="1" data-position="' + predIndx + '">' +
                    //     '   <td colspan="3" class="comboCount">1</td>' +
                    //     '</tr>';
                    ncmComboItem.preDefined = true;
                    preSelectEx.push({
                        predIndx: predIndx,
                        itemId: val["id"]
                    });
                    return;
                }

                var cat = ncmGlobals.settings[0]['itemsCategories'][catId].name;
                var max = parseInt(val["units"]);
                var indexes = arraySearch(arr, 'categoryId', catId, true);
                var inCount = indexes.length;
                var i = 0;

                row += '<tr class="bg-light lter text-md text-left">' +
                    '   <td colspan="3">' +
                    '       <i class="material-icons text-success m-r chk' + catId + '" style="display:none;">&#xE876;</i>' +
                    '       <span class="font-bold">' + cat + '</span>' +
                    '       <span class="text-muted text-xs">' + max + ' artículo(s)</span>' +
                    '   </td>' +
                    '</tr>';

                while (i < inCount) {
                    var c = indexes[i];
                    var product = arr[c];

                    if (!ncmHelpers.validity(product['isParent']) && $.inArray(product['type'], ['product', 'production', 'direct_production', 'compound', 'combo', 'dynamic']) > -1) {
                        var name = product['name'];
                        var id = product['itemId'];
                        var discount = iftn(product['discount'], false);
                        var price = product['price'];
                        var inventory = '';

                        if (discount) {
                            discount = Math.abs(price * (discount / 100));
                            discount = price - discount;
                            fNops.number = discount;
                            price = '<strike class="text-xs text-danger block">' + price + '</strike>' + ncmMaths.formatNumber(fNops);
                        }

                        price = '';
                        var extraClass = '';

                        if (!checkIfEnoughStock(c)) {
                            extraClass = 'text-l-t disabled';
                        }

                        row += '<tr class="text-left blink b-t b-light" data-id="' + id + '" data-position="' + c + '" data-cat="' + catId + '">' +
                            '   <td class="text-md comboCount" style="width:10%;"></td>' +
                            '   <td class="clickeable ' + extraClass + '" data-type="itemFromComboList" style="width:80%;" data-cat="' + catId + '" data-max="' + max + '"> ' +
                            name +
                            '   </td>' +
                            '   <td class="text-right" style="width:10%;">' +
                            '       <a href="#" class="btn clickeable" style="display:none;" data-type="itemFromComboList" data-remove="true" data-cat="' + catId + '" data-max="' + max + '">' +
                            '           <i class="material-icons text-danger">remove</i>' +
                            '       </a>' +
                            '   </td>' +
                            '</tr>';
                    }

                    i++;
                }

                ncmComboItem.totalNeeded += max;
            });

            ncmComboItem.preDefined = false;

        } else {
            ncmAlerts.toast('No posee compuestos', 'danger');
            return;
        }

        row += '<tr>' +
            '   <td colspan="3" class="no-padder text-center">' +
            '       <a href="#" class="btn btn-lg btn-info btn-rounded clickeable text-u-c font-bold" data-comboIndex="' + index + '" data-type="comboConfirm" data-ctype="' + arr[index].type + '">Añadir</a>' +
            '   </td>' +
            '</tr>' +
            '<tr>' +
            '   <td colspan="3"></td>' +
            '</tr>' +
            '<tr><td colspan="3"></td></tr>';

        $('.comboList').append(row);

        callback && callback();

        ncmEvents.a();

        $.each(preSelectEx, function (i, val) {
            if ($('#modalCombo tr[data-id="' + val + '"] td.clickeable').length > 0) {
                $('#modalCombo tr[data-id="' + val + '"] td.clickeable').trigger('click');
            } else {
                $('.comboList').append(`
                    <tr class="hidden" data-id="${val.itemId}" data-preselected="1" data-position="${val.predIndx}">
                        <td colspan="3" class="comboCount">1</td>
                    </tr>
                `)
            }
        });

    }
};

var ncmUser = {
    modal: function (options) {
        options = options || {};

        var itemIndex = options.hasOwnProperty('itemIndex') ? options.itemIndex : -1;
        var type = options.hasOwnProperty('type') ? options.type : ncmTransactions.finalType();
        var callback = options.hasOwnProperty('callback') ? options.callback : '';
        itemIndex = itemIndex > -1 ? itemIndex : '';

        var out = '<div class="col-xs-12 no-padder m-b-sm"><img src="' + window.assetsUrl + 'images/emptystate2.png" width="60%" class="m-t-md"><div class="text-center m-t-sm m-b h4">No se encontraron usuarios</div></div>';
        var row = [];
        var length = ncmGlobals.users.length;

        if (length > 0) {
            $.each(ncmGlobals.users, function (i, user) {

                var id = user.userId;
                var name = user.name;
                var index = i;
                var add = true;
                var color = '';

                if (type === 13) {
                    if (user.inCalendar < 1) {
                        add = false;
                    }
                } else if (type === 10) {
                    if (!user.role == 6) {
                        add = false;
                    }
                } else {
                    /*if(user.role < 3){
                        console.log('role',user.role);
                        add = false;
                    }*/
                }

                if (user.outlet && (user.outlet != ncmTransactions.cOutletData().outletId)) {
                    add = false;
                }

                if (ncmHelpers.validity(user.color)) {
                    color = 'style="border-left:4px solid #' + user.color + '"';
                }

                if (add) {
                    row.push('<tr class="text-left usersFromList b-b pointer" data-position="' + i + '" data-id="' + id + '" data-item="' + itemIndex + '" ' + color + '>');
                    row.push('<td> <div class="font-bold">' + name + '</div> </td>');
                    row.push('</tr>');
                }
            });

            out = '<div class="col-xs-12 wrapper">' +
                '   <div class="h1 font-bold text-left m-b">' +
                '       <div class="text-md font-default">Recursos y</div>Usuarios' +
                '   </div>' +
                '   <input type="search" class="form-control bg-light lter no-border rounded input-lg datatableFilter" placeholder="Buscar..." value="" autocomplete="off">' +
                '   <table class="table" id="tableColaborators"><thead><tr><td></td></tr></thead><tbody>' + row.join('') + '</tbody></table>' +
                '</div>';
        }

        imodaler({
            element: $('#modalNarrow'),
            content: out,
            empty: true,
            onAfter: function ($modal) {
                oneClickWrap('tr.usersFromList', function (event, tis) {
                    var id = tis.data('id');
                    var usrName = arraySearchAndReturn(ncmGlobals.users, 'userId', id, 'name');
                    var itemIndex = parseInt(tis.data('item'));

                    if (itemIndex > -1) {//añado usuario a item
                        window.itemsObj[itemIndex].user = id;
                    } else if (ncmOrders.panel.addUserToOrder) {
                        var orderId = ncmOrders.panel.addUserToOrder;

                        var url = masterUrl + 'action?l=' + ncmHttp.masterUrlParams({ action: 'setUserToOrder', id: orderId, uid: id });

                        ncmHttp.get({
                            url: url,
                            onSuccess: (data) => {
                                ncmAlerts.toast(usrName + ' fue asignado', 'success');
                                ncmOrders.panel.addUserToOrder = false;
                            },
                            onFail: (data) => {
                                ncmAlerts.toast('No se pudo asignar a la orden', 'danger');
                                ncmOrders.panel.addUserToOrder = false;
                            }
                        });
                    } else if (ncmSpaces.userToSpace) {
                        var spaceID = ncmSpaces.userToSpace;

                        var url = masterUrl + 'action?l=' + ncmHttp.masterUrlParams({ action: 'setUserToSpace', id: spaceID, uid: id });

                        ncmHttp.get({
                            url: url,
                            onSuccess: (data) => {
                                ncmAlerts.toast(usrName + ' fue asignado', 'success');
                                ncmSpaces.userToSpace = false;
                                ncmSpaces.action('show', () => {
                                    ncmEvents.a();
                                    loadToolTip(false, true);
                                    ncmUIX.uiHeightsAndSpaces();
                                });
                            },
                            onFail: (data) => {
                                ncmAlerts.toast('No se pudo asignar', 'danger');
                                ncmSpaces.userToSpace = false;
                            }
                        });
                    } else {//añado usuario a la venta
                        ncmTransactions.user = { 'id': id, 'name': usrName };

                        $.each(window.itemsObj, function (i, item) {
                            /*if(item.user == ncmAuth.activeUser.activeUserId && item.type != 'combo'){
                                window.itemsObj[i].user = id;
                            }*/

                            //si un producto no tiene user asignado le asigno el de la venta
                            if (!ncmHelpers.validity(item.user) || item.user == ncmAuth.activeUser.activeUserId) {
                                window.itemsObj[i].user = id;
                            }
                        });
                    }

                    tables('items');
                    options.onSubmit && options.onSubmit();
                    $('#modalNarrow').imodal('hide');
                });

                loadJQDataTable({
                    input: $('input.datatableFilter'),
                    table: $('#tableColaborators'),
                    orderable: { orderable: false, targets: [0] },
                    focus: true
                });
            },
            onDismiss: options.onDismiss,
            onHidden: options.onHidden
        });
    },
    allow: function (section, action, bool) {
        if (section && action) {
            var caja = ncmAuth.activeUser.permissions.register;
            if (caja[section]) {
                if (caja[section][action]) {
                    return true;
                } else {
                    return false;
                }
            } else {
                return false;
            }
        } else {
            return true;
        }
    }
};

var tables = (type, callback) => {
    thalog('tables fn: ' + type);

    if (type == 'items') {
        //Buscador por codigo de barra entra aca
        var registerTable = $('#registerTable');

        registerTable.html('');
        var customer = customerToTable();
        var note = noteToTable();
        var newser = userToTable();
        var saleItems = itemsToTable();
        var clearBtn = $('#clearSaleBtn').html();
        var lastItem = $('#lastItem').html();

        var cartEmpty = $('#cartEmpty').html();


        //var saleList      = (saleItems)?saleItems+clearBtn+lastItem:cartEmpty;
        if (saleItems) {
            registerTable.addClass('momentumit');
            var saleList = saleItems + clearBtn + lastItem;
        } else {
            registerTable.removeClass('momentumit');
            var saleList = cartEmpty;
            //ncmTransactions.returnMode    = false;
            //ncmTransactions.quoteMode     = false;
        }
        var html = '<div class="animated speed-5x col-xs-12 no-padder" id="registerTableListWrapper">' + newser + customer + note + saleList + '</div>';
        // Agregando producto a la lista
        registerTable.html(html, function () {
            $('#logoSaleList').css('margin-top', (((ncmUIX.windowH - 237) / 2) - 30) + 'px');
            ncmEvents.change();
            ncmEvents.a();
            ncmEvents.hoverable();

            ncmHelpers.onClickWrap('.imodalopen', function (event, tis) {
                var element = tis.data('imodal');
                $(element).imodal('show');
            });

            /*if(ncmTransactions.returnMode){
                currentSaleModeUI('return');
            }else if(!ncmTransactions.tableNo){
                currentSaleModeUI();
            }else if(ncmTransactions.quoteMode){
                currentSaleModeUI('quote');
            }else{
                currentSaleModeUI();
            }*/

            checkPermissions();

            callback && callback(html);
        });

        ncmTransactions.updatePrice();

        if ($.inArray(ncmTransactions.finalType(), [0, 3]) > -1) {
            ncmWebSockets.checkoutScreen();
        }

    } else if (type == 'payment') {

        var out = '';

        $('#paymentTable tbody').html(out);

        var n = window.paymentsObj.length,
            tr = '';
        if (n > 0) {

            var fNops = {
                number: 0
            };

            for (var i = 0; i < n; i++) {
                name = window.paymentsObj[i].name;
                extra = window.paymentsObj[i].extra;
                type = window.paymentsObj[i].type;
                index = i;
                price = window.paymentsObj[i].price;

                if (type == 'check') {
                    extra = explodes(extra, ';', false, 1);
                }

                if (name && price) {
                    fNops.number = price;
                    fNops.currency = true;
                    tr += '<tr class="no-hover text-u-c font-bold"><td class="text-left text-muted">' + name + '</td><td class="text-center text-muted">' + extra + '</td><td class="text-right">' + ncmMaths.formatNumber(fNops) + '</td><td class="text-right"><a href="javascript:;" class="clickeable text-md m-t-md" data-position="' + index + '" data-type="rmPayment"><i class="material-icons text-danger">close</i></a></td></tr>';
                }
            }

            $('#paymentTable tbody').html(tr, function () {
                ncmEvents.change();
                ncmEvents.a();
                ncmEvents.hoverable();
                callback && callback();
            });
        }

        ncmTransactions.updatePrice();
    }
};



var orderTableItemsArray = function () {
    if (ncmHelpers.validity(window.itemsObj, 'object')) {
        $.each(window.itemsObj, function (k, val) {
            if ('type' in val && val.type == 'discount') {//si hay un descuento lo meto al final de la lista
                //re calculo el total de la venta
                var saleSubtotal = ncmTransactions.updatePrice('subtotal');

                if (val.exchange == '$') {//se añadio como porcentaje
                    val.discount = (val.totalDiscount * 100) / saleSubtotal;
                } else {
                    var newVal = (val.discount * saleSubtotal) / 100;
                    val.price = newVal;
                    val.total = newVal;
                    val.totalDiscount = newVal;
                    val.uniPrice = newVal;
                }

                window.itemsObj.push(window.itemsObj.splice(k, 1)[0]);
            }
        });
    }
};

var itemsToTable = function () {
    thalog('itemsToTable fn');

    var n = window.itemsObj.length;
    var itemsList = '';
    var stDecimal = ncmHelpers.valid(ncmGlobals.settings[0], 'decimal');
    var stThousandSep = ncmHelpers.valid(ncmGlobals.settings[0], 'thousandSeparator');
    var stCurrency = ncmMaths.setCurrency('symbol');
    var cgTaxable = window.taxable;

    var fNops = {
        number: 0
    };

    ncmCalendar.scheduleDuration = 0;

    //ordeno itemsarray
    orderTableItemsArray();

    for (var i = 0; i < n; i++) {
        var item = window.itemsObj[i];

        if (!ncmHelpers.validity(item)) {
            continue;
        }
        //if(item.count < 0){ncmTransactions.returnMode = true;}

        var product = ncmHelpers.getProduct(item.itemId);
        var pIndex = product.index;

        var index = i;
        var itemId = item.itemId;

        var displayPrice = item.displayPrice;
        var price = item.price;
        var count = iftn(item.count, 1);
        var discount = iftn(item.discount, false);
        var note = ncmHelpers.markupt2HTML({
            text: item.note,
            type: 'MtH'
        });

        var tagsin = iftn(item.tags, false);
        var total = item.total;

        var name = iftn(item.name, product.name);
        var sku = item.uId;
        var uPrice = item.price;
        var tax = iftn(item.tax, false);
        var type = item.type;
        var duration = item.duration * count;
        var kind = item.kind;
        var hasParent = item.parent;

        var itmUser = false;
        var btnDisabled, cntDisabled;
        var hideLast = '';
        var isProduct = false;
        var isInCombo = false;
        var isInComboAd = false;
        var isCombo = false;
        var isGiftcard = false;
        var isDiscount = false;
        var isCredit = false;
        var isChildren = false;
        var out = '';
        var result = {};

        var durationName = '';
        if (duration && duration > 0) {
            durationName = ' <span class="badge bg-light lter font-normal" id="itmDuration' + i + '">' + convertMinsToHrsMins(duration) + '</span>';
            ncmCalendar.scheduleDuration += duration;
        }

        if ($.inArray(type, ['product', 'direct_production', 'production', 'dynamic']) !== -1) {
            isProduct = true;
        }
        if (type == 'inCombo') {
            isInCombo = true;
        }
        if (type == 'inComboAddons') {
            isInComboAd = true;
        }
        if ($.inArray(type, ['combo', 'comboAddons']) !== -1) {
            isCombo = true;
        }
        if (type == 'giftcard') {
            isGiftcard = true;
        }
        if (type == 'inCredit') {
            isCredit = true;
        }
        if (type == 'discount') {
            isDiscount = true;
        }

        if (cgTaxable) {
            tax = ncmMaths.getTaxOfPrice(tax, price);

        } else {
            tax = 0;
        }

        if (item.user && item.user != 'false' && item.user != ncmAuth.activeUser.activeUserId) {
            var usrI = arraySearch(ncmGlobals.users, 'userId', item.user);
            if (usrI > -1) {
                itmUser = ncmGlobals.users[usrI].name;
            }
        }

        var fAmount = ncmMaths.formatNumber({ number: total, decimal: ncmGlobals.settings[0].decimal });
        var fPrice = ncmMaths.formatNumber({ number: price, decimal: ncmGlobals.settings[0].decimal });
        var fDiscount = ncmMaths.formatNumber({ number: discount });

        if (type == 'dynamic' && note) {
            name = note;
        }

        var itemTagsLine = iftn(tagsin, '', displaySelectedTags(tagsin).join(' - '));
        var dataText = [
            itemId + ' @ ' + iftn(displayPrice, fPrice),
            iftn(itmUser, '', '<i class="material-icons m-l-xs md-14">&#xe851;</i> ' + itmUser),
            iftn(itemTagsLine, '', '<i class="material-icons m-l-xs md-14">&#xe893;</i> ' + itemTagsLine),
            iftn(note, '', '<i class="material-icons m-l-xs md-14">&#xe0cb;</i> ' + note)
        ].join(' ');

        if (isProduct) {
            var discountBg = 'bg-light';
            var discountBorder = (discount) ? 'b-l b-3x b-warning' : '';

            var result = {
                isItem: {
                    index: index,
                    id: itemId,
                    name: name,
                    qty: count,
                    qtyRaw: count,
                    price: fPrice,
                    priceRaw: price,
                    amount: fAmount,
                    amountRaw: total,
                    duration: durationName,
                    discount: ((discount) ? fDiscount : false),
                    discountBg: discountBg,
                    discountBorder: discountBorder,
                    parent: item.parent,
                    data: dataText
                }
            };

        } else if (isCombo) {
            var amount = ncmMaths.formatNumber({ number: total });
            var price = ncmMaths.formatNumber({ number: price });

            var result = {
                isCombo: {
                    index: index,
                    id: itemId,
                    name: name,
                    amount: fAmount,
                    amountRaw: total,
                    duration: durationName,
                    data: dataText
                }
            };

        } else if (isInCombo && !ncmGlobals.settings[0].hideCombo) {
            var amount = ncmMaths.formatNumber({ number: total });

            var result = {
                inCombo: {
                    index: index,
                    id: itemId,
                    name: name,
                    qty: count,
                    qtyRaw: count,
                    oQty: count,
                    data: iftn(itmUser, '')
                }
            };
        } else if (isInComboAd && !ncmGlobals.settings[0].hideCombo) {
            var amount = ncmMaths.formatNumber({ number: total });

            var result = {
                inCombo: {
                    index: index,
                    id: itemId,
                    name: name,
                    amount: fAmount,
                    amountRaw: total,
                    qty: count,
                    qtyRaw: count

                }
            };

        } else if (isGiftcard) {
            var amount = ncmMaths.formatNumber({ number: total });
            var price = ncmMaths.formatNumber({ number: price });

            var result = {
                isGiftCard: {
                    index: index,
                    id: itemId,
                    name: name,
                    amount: fAmount,
                    amountRaw: total,
                    discount: ((discount) ? fDiscount : false),
                    color: iftn(item.giftcardColor, 'gradBgOrange', ''),
                    colorCss: iftn(item.giftcardColor, '', 'background:#' + item.giftcardColor),
                    data: dataText
                }
            };

        } else if (isCredit) {
            var amount = ncmMaths.formatNumber({ number: total });

            var result = {
                isCredit: {
                    index: index,
                    id: itemId,
                    name: name,
                    amount: amount,
                    data: dataText
                }
            };

        } else if (isDiscount) {

            var percent = ncmMaths.formatNumber({ number: discount, decimal: 'no' });
            var amount = ncmMaths.formatNumber({ number: total });

            var result = {
                isDiscount: {
                    index: index,
                    id: itemId,
                    percent: percent + '%',
                    amount: amount
                }
            };

        } else if (type == "comboDiscount") {
            var result = {};
        } else if (type == 'info') {
            var out = '<span class="inthelist block" data-position="' + index + '" style="height:80px; overflow-y:hidden; ' + hideLast + '">';
            out += '<div class="main wrapper-md bg" style="width:100%;">';
            fNops.number = total;
            out += '<div class="pull-right m-t-sm m-l-xs text-md">' + ncmMaths.formatNumber(fNops) + '</div>';
            out += '<div class="clear"> <span class="block text-ellipsis">' + name + '</span> </div>';

            out += '</div></span>';
        }

        var out = ncmUIX.mustache(false, result, $('#itemLineTpl'));

        itemsList += out;

        delete index, itemId, name, sku, price, uPrice, count, discount, note, tax, type, total;
    }

    return itemsList;
};

