var calculateComboDiscounts = function (combo, compounds, note, count) {
    var coParent = mt_rand();
    var totalComboPrice = 0;
    var iInCombo = 0;

    combo.price = ncmMaths.parseFloatSafe(combo.price);//aseguro que sea numerico y no string

    if (combo.fixedDiscount > 0) {
        combo.price = ncmMaths.rule3Simple(combo.fixedDiscount, combo.price);
        combo.fixedDiscount = 0;
    }

    var options = {
        id: combo.itemId,
        uId: combo.sku,
        name: combo.name,
        price: combo.price,
        tax: combo.tax,
        type: 'combo',
        count: iftn(count, 1),
        parent: coParent,
        note: note
    };

    ncmItems.insert(options);

    var topComboPriceList = [];
    $.each(compounds, function (i, v) {
        var index = arraySearch(ncmGlobals.products, 'itemId', v.id);
        if (index > -1) {
            var pro = ncmGlobals.products[index];



            var price = ncmMaths.parseFloatSafe(pro.price);
            if (pro.fixedDiscount > 0) {
                pro.price = ncmMaths.rule3Simple(pro.fixedDiscount, pro.price);
                pro.fixedDiscount = 0;
            }
            topComboPriceList.push(pro.price);

            var units = ncmMaths.parseFloatSafe(v.units);

            totalComboPrice += price * units;
            iInCombo += units;

            v.index = index;
            v.price = price;
            v.units = units; //paso a number
        }
    });

    var totalItems = compounds.length;

    if (ncmHelpers.valid(combo, 'priceRule')) {

        var coArray = $.parseJSON(combo.compound);
        var maxInCombo = parseInt(coArray[0].units ? coArray[0].units : 1);

        if (combo.priceRule == 'topPrice') {
            totalComboPrice = Math.max.apply(null, topComboPriceList);
        } else if (combo.priceRule == 'lowPrice') {
            totalComboPrice = Math.min.apply(null, topComboPriceList);
        } else if (combo.priceRule == 'average') {
            totalComboPrice = totalComboPrice;
        }

        var eachPrice = totalComboPrice;
        var eachQty = 1 / (maxInCombo ? maxInCombo : totalItems);

    } else {

        if (totalComboPrice > combo.price && combo.price > 0) {
            var restPrice = ncmMaths.resta(totalComboPrice, combo.price);
            var allCompPrice = 0;

            $.each(compounds, function (i, v) {
                restPrice = ncmMaths.divider(restPrice, v.units);
                if (restPrice > 0) {

                    var price = v.price;
                    if (restPrice >= price) {
                        rest = ncmMaths.resta(restPrice, price);
                        v.price = 0;
                    } else {
                        v.price = ncmMaths.resta(price, restPrice);
                        rest = 0;
                    }

                    allCompPrice += v.price;

                    restPrice = rest;
                }
            });
        }

    }

    if (combo.kind == 'comboAddons') {
        var cCInx = arraySearch(window.itemsObj, 'parent', coParent);

        if (cCInx > -1) {
            window.itemsObj[cCInx].displayPrice = ncmMaths.formatNumber({ number: totalComboPrice, decimal: ncmGlobals.settings[0].decimal });
        }
    }

    //

    $.each(compounds, function (i, v) {
        var index = v.index;
        var p = ncmGlobals.products[index];
        if (p) {
            var options = {
                id: p.itemId,
                uId: p.sku,
                name: '↳' + p.name,
                tax: p.tax,
                discount: p.fixedDiscount,
                count: v.units,
                parent: coParent,
                duration: p.duration
            };

            if (combo.kind == 'comboAddons') {
                options.type = 'inComboAddons';

                if (ncmHelpers.valid(combo, 'priceRule')) {
                    if (combo.priceRule == 'average') {
                        options.price = ((v.price) ? v.price : p.price);
                    } else {
                        options.price = eachPrice;
                    }
                    options.count = eachQty * options.count;
                } else {

                    if (p.fixedDiscount > 0) {
                        p.price = ncmMaths.rule3Simple(p.fixedDiscount, p.price);
                        p.fixedDiscount = 0;
                    }
                    options.price = (v.price) ? v.price : p.price;
                }

            } else {
                options.type = 'inCombo';
                options.price = 0;//v.price;
            }

            ncmItems.insert(options);
        }
    });

    tables('items');
    //ncmAlerts.toast('Agregado','success');
};

