var getProductField = function (field, match, against) {
    if (!field || !match || !against) { return false; }
    var index = arraySearch(ncmGlobals.products, match, against);
    if (index) {
        var found = ncmGlobals.products[index][field];
        if (found) {
            return found;
        } else {
            return false;
        }
    } else {
        return false;
    }
};

var updateItemFinalPrice = function (index) {
    thalog('updateItemFinalPrice fn');

    var item = window.itemsObj[index];
    var discount = iftn(item.discount, 0);
    var count = iftn(item.count, 1);
    // var price           = iftn(item.uniPrice * count, 0);

    item.price = item.uniPrice - ncmMaths.addDiscount(discount, item.uniPrice);
    item.total = iftn(item.price * count, 0);
};

var paymentMethodProcessFn = function (coin, name, price, extra, callback) {
    thalog('paymentMethodProcessFn fn');

    var toPay = ncmTransactions.updatePrice('topay');
    var go = true;

    toPay = ncmMaths.formatNumber({ number: toPay, typing: true, raw: true });

    $.each(window.paymentsObj, function (i, val) {
        if (coin == 'giftcard' && extra == val.extra) {
            go = false;
        }
    });

    if (!go) {
        ncmAlerts.toast('No puede añadir el mismo método', 'warning');
        return false;
    }

    object = { 'type': coin, 'name': name, 'price': price, 'total': toPay, 'extra': extra };
    window.paymentsObj.push(object);

    tables('payment');

    var toPay = ncmTransactions.updatePrice('topay');//obtengo el topay actualizado luego del push

    $('#tendered').val(toPay);
    var fNops = {
        number: toPay
    };
    $('#payText').html('<span class="text-lighter">' + ncmMaths.setCurrency('symbol') + '</span>' + ncmMaths.formatNumber(fNops));

    if (ncmMaths.parseFloatSafe(toPay) < 0.001) {
        var toPayTxt = ncmMaths.setCurrency('symbol') + ncmMaths.formatNumber({ number: Math.abs(toPay) });
        $('#confirmScreen .confirmChange').text(toPayTxt);

        if (Math.abs(toPay) > 0) {
            $('.confirmChange').addClass('pointer text-u-l');
            ncmHelpers.click('.confirmChange', function (event, tis) {

                var options = {
                    title: 'Ingrese la propina',
                    nType: 'qty',
                    operatorbtn: '-',
                    value: Math.abs(toPay)
                };

                numberPad(options, (tipValue) => {
                    if (ncmHelpers.validity(tipValue)) {
                        tipValue = ncmMaths.parseFloatSafe(tipValue);

                        if (tipValue) {
                            var data = { 'amount': tipValue, 'date': getFullDateAndTime(), 'note': 'PROPINA' };
                            var store = { 'drwrIncome': data, 'uid': ncmHelpers.generateUid() };
                            ncmHttp.saveDataLocally(store, (back) => {
                                if (back) {

                                    ncmAlerts.toast('Propina registrada', 'success');

                                    var toPayTxt = ncmMaths.setCurrency('symbol') + ncmMaths.formatNumber({ number: (Math.abs(toPay) - tipValue) });
                                    $('#confirmScreen .confirmChange').text(toPayTxt);

                                } else {
                                    ncmAlerts.toast('No pudimos registrar la propina', 'danger');
                                }
                            });
                        }
                    }
                });

            });
        }

        var typePrint = 'autoPrint';

        if (ncmHelpers.valid(ncmTransactions, 'creditPayment') || ncmHelpers.valid(ncmTransactions, 'saleInternal')) {
            typePrint = 'receiptPrint';
        }

        if ($('#modalPay').is(':visible')) {//si no hay ident de pago

            imodaler({
                element: $('#modalPay'),
                hide: true,
                onHidden: function (tis) {

                    ncmTransactions.process(function () {
                        ncmPrinters.justPrint(typePrint);
                    });

                    ncmEvents.unHashUrl();
                    tis.find('.btn-numpad').off('click');

                }
            });

        } else {//aqui es si ingrese un ident de pago que cubrio el total
            ncmTransactions.process(function () {
                ncmPrinters.justPrint(typePrint);
            });
        }
    } else {
        ncmTransactions.updatePrice();
        callback && callback();
    }
};

var payAllTransactions = function (data, callback) {

    if (!ncmHelpers.validity(ncmTransactions.parentSaleId, 'string')) {//son varias cuentas
        var parents = ncmTransactions.parentSaleId;
        var remain = data.total;

        $.each(parents, function (transId, debt) {
            //var debt          = val.total;
            data.parentId = transId;
            data.invoiceno = data.invoiceno + 1;

            if (remain > 0) {
                if (remain >= debt) { //si paga mas que la primera deuda
                    data.total = debt; // cubro todo exacto
                    data.subtotal = debt; // cubro todo exacto
                    remain = remain - debt;
                } else {
                    data.total = remain;
                    data.subtotal = remain;
                    remain = 0;
                }

                //var store         = {'transaction':data};
                callback && callback(data);
            }
        });
    } else {
        callback && callback(data);
    }
};

var paymentMethodFn = function (coin, name, price) {
    price = ncmMaths.parseFloatSafe(price);
    if (ncmHelpers.validity(window.itemsObj) && (price >= 0 || ncmTransactions.ePOSCustomAmount)) {
        var noIdentifiers = ['cash', 'check', 'points', 'storeCredit', 'giftcard', 'QRPayment', 'ePOSCard', 'pix'];
        if ($.inArray(coin, noIdentifiers) < 0 && ncmGlobals.settings[0].paymentMethodId > 0) {
            var options = {
                title: 'Ingrese el identificador de pago'
            }
            ncmAlerts.prompt(options, function (paymentId) {
                if (ncmHelpers.validity(paymentId)) {
                    paymentMethodProcessFn(coin, name, price, paymentId, function () {
                        payPad();
                    });
                } else {
                    payPad();
                }
            });
        } else if (coin == 'points') {
            if (price > ncmMaths.parseFloatSafe(ncmTransactions.customer.loyalty)) {
                ncmAlerts.nativeAlert('No posee crédito suficiente', 'danger');
            } else {
                paymentMethodProcessFn(coin, name, price, '');
            }
        }
        else if (coin == 'storeCredit') {
            if (price > ncmMaths.parseFloatSafe(ncmTransactions.customer.storeCredit)) {
                ncmAlerts.nativeAlert('No posee crédito suficiente', 'danger');
            } else {
                paymentMethodProcessFn(coin, name, price, '');
            }
        }
        else if (coin == 'giftcard') {
            var options = {
                title: 'Ingrese el código del Gift Card',
                allowDecimals: 'no',
                nType: 'qty'
            }

            numberPad(options, function (prompt) {
                if (ncmHelpers.validity(prompt)) {
                    var url = masterUrl + 'action?l=' + ncmHttp.masterUrlParams({ action: 'chkGiftCard', id: prompt, type: 'bool', amount: price });
                    ncmHttp.getit(url, function (result) {
                        if (result.success == 'deactivated') {
                            ncmAlerts.nativeAlert('Gift Card inhabilitada', 'danger', function () {
                                payPad();
                            });
                        } else if (result.success == 'expired') {
                            ncmAlerts.nativeAlert('Gift Card Vencida', 'danger', function () {
                                payPad();
                            });
                        } else if (result.success == 'used') {
                            ncmAlerts.nativeAlert('Gift Card sin fondos', 'danger', function () {
                                payPad();
                            });
                        } else if (result.success == 'notenough') {
                            ncmAlerts.nativeAlert('Gift Card no posee suficientes fondos', 'danger', function () {
                                payPad();
                            });
                        } else if (result.success == 'true') {
                            //aqui uso la gift
                            paymentMethodProcessFn(coin, name, price, prompt, payPad);

                        } else {
                            ncmAlerts.nativeAlert('Gift Card inexistente', 'danger', function () {
                                payPad();
                            });
                        }
                    }, function (result) {
                        ncmAlerts.nativeAlert('Gift Card inexistente', 'danger', payPad);
                    }, false, 'json');
                }
            });
        }
        else if (coin == 'check' && ncmGlobals.settings[0].paymentMethodId > 0) {

            imodaler({
                element: $('#modalBankPicker'),
                onBefore: bankListFn(),
                onAfter: function () {
                    ncmDatePicker.input({
                        element: '#checkBankPaymentExpiration',
                        defaultDate: moment().add(1, 'month')
                    });
                },
                onHidden: function ($tis) {
                    var bank = $('#modalBankPicker #checkBankPayment').val();
                    var nro = $('#modalBankPicker #checkBankPaymentNumber').val();
                    var expires = $('#modalBankPicker #checkBankPaymentExpiration').val();

                    if (ncmHelpers.validity(bank) && ncmHelpers.validity(nro) && ncmHelpers.validity(expires)) {

                        paymentMethodProcessFn(coin, name, price, bank + ';' + nro + ';' + expires, function () {
                            payPad();
                        });

                    } else {
                        payPad();
                    }

                    $('#modalBankPicker #checkBankPayment, #modalBankPicker #checkBankPaymentNumber, #modalBankPicker #checkBankPaymentExpiration').val('');
                }
            });
        }
        else if (coin == 'pix') {

            var pixCustomer = '';
            var pixCustomerPhone = '0999999999';
            var pixCustomerEmail = '<?= EMAIL_FROM ?>';

            if (ncmHelpers.valid(ncmTransactions, 'customer')) {
                if (ncmHelpers.valid(ncmTransactions.customer, 'phone')) {
                    pixCustomerPhone = ncmTransactions.customer.phone
                }

                if (ncmHelpers.valid(ncmTransactions.customer, 'email')) {
                    pixCustomerEmail = ncmTransactions.customer.email
                }

                pixCustomer = ncmTransactions.customer.name;

            } else {
                ncmAlerts.alert({ title: "Debe añadir un cliente", type: "warning" });
                return false;
            }

            var $container = $('#modalNarrow .imodal-body');

            imodaler({
                element: $('#modalNarrow'),
                contentNoWrap: true,
                fixed: false,
                onBefore: async function () {
                    $container.removeClass('wrapper').addClass('no-padder');
                    $container.addClass('bg-white');
                    $container.html('');
                    ncmTransactions.trUID = numuid();

                    ncmPayments.ops = { container: $container, coin: coin, name: name, price: ncmTransactions.updatePrice('topay') };

                    var online = true;
                    checkInternet();
                    if (window.isServerOnline === false) {
                        online = false
                    }

                    ncmUIX.mustache(ncmPayments.container, { pixDatas: true }, $('#qrPixPaymentTpl'));

                    $("#PixPaymentBtnSubmit").on("click", async function () {
                        var description = "Pago a " + ncmGlobals.settings[0].companyName;
                        var cpf = $("#PixCpfInput").val();
                        if (ncmHelpers.validity(cpf) && cpf.length >= 5) {
                            if (online) {
                                var dataPix = {
                                    pixCustomer: pixCustomer,
                                    pixDescription: description,
                                    pixCpf: cpf,
                                    pixCustomerPhone: pixCustomerPhone,
                                    pixCustomerEmail: pixCustomerEmail
                                }
                                ncmPayments.pix.qr.load(dataPix);
                            } else {
                                ncmAlerts.alert({ title: "ERROR: No se puede realizar esta operación sin conexión a Internet", type: "danger" });
                                return false;
                            }
                        } else {
                            ncmAlerts.toast("La descripción y el cpf deben tener al menos 5 caracteres", "warning");
                        }
                    });
                },
                onAfter: () => {
                    ncmUIX.setDarkMode();
                },
                onHidden: () => {
                    $('#modalNarrow .imodal-body').removeClass('bg-white');
                    ncmWebSockets.checkoutScreen();
                },
                contentNoWrap: true
            });
        }
        else if ($.inArray(coin, ['QRPayment', 'ePOSCard', 'ePOS']) > -1) {

            var $container = $('#modalNarrow .imodal-body');

            imodaler({
                element: $('#modalNarrow'),
                contentNoWrap: true,
                fixed: false,
                onBefore: async function () {

                    $container.removeClass('wrapper').addClass('no-padder');
                    $container.addClass('bg-white');
                    $container.html('');
                    ncmTransactions.trUID = numuid();

                    ncmPayments.ops = { container: $container, coin: coin, name: name, price: ncmTransactions.updatePrice('topay') };

                    var online = true;
                    checkInternet();
                    if (window.isServerOnline === false) {
                        online = false
                    }

                    var prev = '   <div class="col-sm-6 col-xs-12 col-sm-offset-3 wrapper">' +
                        '       <div class="col-xs-12 font-bold text-center h4 wrapper">' +
                        '           <img style="font-size: 60px !important; height: 60px;" src="/images/svg-loaders/puff.svg" width="60"></img>' +
                        '           <div>Cargando...</div>' +
                        '       </div>' +
                        '   </div>';

                    ncmPayments.container.html(prev);

                    var posConnected = await ncmPayments.cajaPOS.isPosConnected();

                    if (online) {

                        if (posConnected) { // Pos Físico Vinculado
                            if (coin == 'QRPayment' || coin == 'ePOS') {
                                //qr bancard 
                                ncmPayments.cajaPOS.qr.load();
                            } else if (coin == 'ePOSCard') {
                                ncmPayments.cajaPOS.card.load();
                            }
                        } else {
                            if (coin == 'QRPayment' || coin == 'ePOS') {
                                //qr bancard
                                ncmPayments.ePOS.qr.load();
                            } else if (coin == 'ePOSCard') {
                                ncmPayments.ePOS.card();
                            }
                        }
                    } else {
                        ncmAlerts.alert({ title: "ERROR: No se puede realizar esta operación sin conexión a Internet", type: "danger" });
                        return false;
                    }
                },
                onAfter: () => {
                    ncmUIX.setDarkMode();
                },
                onHidden: () => {
                    $('#modalNarrow .imodal-body').removeClass('bg-white');
                    ncmWebSockets.checkoutScreen();
                },
                contentNoWrap: true
            });

        } else {
            paymentMethodProcessFn(coin, name, price, '');
        }


        window.nPtaped = false;
    } else {
        ncmAlerts.toast('Ingrese un monto válido', 'danger');
    }
};

var bankListFn = function () {
    var data = ncmHelpers.getValidObjectStr(ncmGlobals.settings[0].bankNames);
    var length = data.length, row = new Array();

    if (length > 0) {
        for (var r = 0; r < length; r++) {
            if (ncmHelpers.validity(data[r].tagname)) {
                var id = data[r].tagid;
                var name = data[r].tagname;

                row.push('<option value="' + id + '">' + name + '</option>');
            }
        }
    } else {
        row.push('<option value="0">Sin Emisores</option>');
    }
    $('#modalBankPicker #checkBankPayment').html(row.join(""));
}

var justPay = async function () {

    if (ncmTransactions.tableNo || ncmTransactions.customerOrder) {
        //
        if (window.itemsObj.length > 0) {
            ncmTransactions.process(function () {
                ncmPrinters.justPrint('orderPrint');
            });
        } else {
            ncmAlerts.nativeAlert('Debe añadir artículos para realizar una orden', 'danger');
        }
    }
    else if (ncmTransactions.schedule) {

        if (!ncmHelpers.validity(window.fromDate) || !ncmHelpers.validity(window.toDate)) {
            ncmAlerts.toast('Seleccione fecha y horario', 'warning');
            ncmDatePicker.modal({ type: 'hour', source: 'schedule' });
            return false;
        }

        if (!ncmHelpers.validity(ncmTransactions.customer)) {
            ncmAlerts.toast('Añada un cliente', 'warning');
            customersSearchAutocomplete();
            return false;
        }

        if (!ncmHelpers.validity(ncmTransactions.user)) {
            var userInItem = ncmHelpers.validity(window.itemsObj) ? window.itemsObj[0] : {};
            if (!ncmHelpers.validity(userInItem.user)) {
                ncmUser.modal();
                ncmAlerts.toast('Añada un recurso', 'warning');
                return false;
            } else {
                /*var usrCalendar = arraySearchAndReturn(ncmGlobals.users,'userId',userInItem.user);
                if(ncmHelpers.validity(usrCalendar.inCalendar)){
                    ncmTransactions.user = {'id':userInItem.user,'name':usrCalendar.name};
                }else{*/
                ncmUser.modal();
                ncmAlerts.toast('Añada un recurso agendable', 'warning');
                return false;
                //}
            }
        } else {
            var canGo = true;
            var usrs = [];

            usrs.push(ncmTransactions.user.id);

            $.each(window.itemsObj, function (i, val) {
                if (val.user != ncmTransactions.user.id) {
                    canGo = false;
                }

                usrs.push(val.user);
            });

            if (window.appConfigObj[0].appOverlap && usrs.length > 0) {
                usrs = [...new Set(usrs)]; //elimino duplicados
                var cantSet = 'waiting';
                var url = masterUrl + 'action?l=' + ncmHttp.masterUrlParams({ action: 'checkIfUserOccupied', users: usrs, from: window.fromDate, to: window.toDate });
                cantSet = await loadWait({ url: url, type: 'GET', hideloader: true });
                cantSet = ncmHelpers.getValidObjectStr(cantSet);//JSON.parse(cantSet);
                cantSet = Object.assign({}, cantSet);

                if (!ncmHelpers.valid(cantSet, 'error')) {

                    var names = '';
                    $.each(cantSet, function (i, val) {
                        names += arraySearchAndReturn(ncmGlobals.users, 'userId', val, 'name') + ', ';
                    });

                    ncmDialogs.alert('Ya existen citas', 'Seleccione otro horario para ' + names, "warning");
                    return false;

                }
            }

            if (!canGo) {
                ncmAlerts.alert({ "title": "Se generarán varios agendamientos", body: "Si el recurso asignado es distinto al del artículo/servicio se generarán varios bloqueos en la agenda. Desea continuar?", type: 'confirm' }, function (result) {
                    if (result) {
                        ncmTransactions.status = '0';
                        ncmTransactions.process(function () {
                            //ncmPrinters.justPrint('schedulePrint');
                        });
                    }
                });
            } else {
                ncmTransactions.status = '0';
                ncmTransactions.process(function () {
                    //ncmPrinters.justPrint('schedulePrint');
                });
            }
        }

    }
    else {
        window.dueDate = false; //reseteo fecha de vencimiento

        var invoiceAuthAlerts = ncmUIX.invoiceAuthAlerts(true);

        if (!invoiceAuthAlerts) {//si hay un bloqueo no permito seguir
            return false;
        }

        ncmTransactions.bringingSale = [];
        window.itemAltObj = [];

        ncmDrawerManager.manage('pay', function () {
            if (!ncmHelpers.validity(window.isToPay)) {
                total = ncmTransactions.updatePrice('total');
            } else {
                total = window.isToPay;
            }

            var expiresDatePickerConfig = { type: 'expires', addMonth: true, source: 'expires' };
            var register = selectRegisterById(window.appConfigObj[0].registerId);
            var saletype = ncmTransactions.finalType();

            if (register) {
                if (register.electronicInvoice == "1") {
                    if (ncmHelpers.valid(ncmGlobals.settings[0].modules, 'electronicInvoice')) {
                        if (!ncmHelpers.valid(ncmGlobals.settings[0].modules.electronicInvoice, 'status')) {
                            ncmAlerts.alert({ title: "ERROR: Módulo de Factura Electrónica desactivado.", type: "danger" });
                            return false;
                        } else if (saletype == 6 && window.isServerOnline === false) {
                            ncmAlerts.alert({ title: "ERROR: No se puede realizar esta transacción sin conexión a internet.", type: "danger" });
                            return false;
                        }
                    }
                }
            }

            if (window.accessLevel == 'BASIC' && ncmTransactions.finalType() == 0) {//guardo la venta porque es un vendedor
                ncmTransactions.preventDuplicate(function () {
                    ncmTransactions.saveSale({ type: '2' });
                });
            } else {
                if (ncmTransactions.saleCondition && !ncmTransactions.creditPayment) { //si es una venta a crédito

                    if (!ncmHelpers.validity(ncmTransactions.customer)) {
                        ncmAlerts.alert({ title: "Debe añadir un cliente", type: "warning" });
                    } else {
                        var creditLine = 0;
                        if (ncmGlobals.settings[0].forceCreditLine) {//fuerzo linea de credito

                            if (ncmHelpers.validInObject(ncmTransactions.customer, 'creditLine')) {
                                creditLine = ncmMaths.parseFloatSafe(ncmTransactions.customer.creditLine);
                            }

                            if (creditLine >= total) {
                                ncmDatePicker.modal(expiresDatePickerConfig);
                            } else if (creditLine < 1) {
                                ncmAlerts.alert({ title: "El cliente no posee línea de crédito", type: "warning" });
                            } else {
                                ncmAlerts.alert({ title: "Línea de crédito superada", type: "warning" });
                            }
                        } else {//si no fuerzo permito credito para cualquiera
                            ncmDatePicker.modal(expiresDatePickerConfig);
                        }
                    }
                } else if (ncmTransactions.quoteMode) {
                    if (!ncmHelpers.validity(ncmTransactions.customer)) {

                        customersSearchAutocomplete();

                    } else {
                        ncmDatePicker.modal(expiresDatePickerConfig);
                    }
                } else if (ncmTransactions.returnMode) {
                    ncmTransactions.process(function () {
                        ncmPrinters.justPrint('returnPrint');
                    });
                } else {

                    payPad();

                }
            }
        });
    }
};

