var ncmDrawerManager = {
    isOpen: true,
    closedTotal: 0,
    manage: function (type, callback) {
        if (window.accessLevel == 'BASIC') {
            ncmAlerts.toast('No posee permisos', 'warning');
            callback && callback(true);
        } else {
            if (window.appConfigObj[0].drawer) {
                if (type == 'open') {
                    ncmDrawerManager.openClose('open', function () {
                        ncmDrawerManager.isOpen = true;
                        ncmAlerts.toast('Caja Abierta', 'success');
                        ncmDrawerManager.state('show');
                        callback && callback();
                    });
                } else if (type == 'pay') {//para pagar, anular o devolver
                    if (ncmDrawerManager.isOpen) {
                        callback && callback();
                    } else {
                        ncmDrawerManager.openClose('open', function () {
                            ncmDrawerManager.isOpen = true;
                            ncmAlerts.toast('Caja Abierta', 'success');
                            callback && callback();
                        });
                    }
                } else if (type == 'close') {
                    //cierro caja
                    ncmAlerts.alert({ title: "¿Realmente desea realizar el cierre?" }, function (result) {
                        if (result) {
                            ncmDrawerManager.openClose('close', function () {
                                ncmPrinters.justPrint('closeRegPrint');
                                ncmAlerts.alert({ title: "Caja Cerrada", type: "success" });
                                ncmTransactions.clearSale({ loadInterface: true });
                                ncmDrawerManager.isOpen = false;
                                ncmDrawerManager.state('hide');
                            });
                        }
                    });

                } else if (type == 'add') {
                    //agrego monto a la caja, el proceso lo hago a travez del callback
                    callback && callback(true);
                }
            } else {
                $('#logoSaleList').attr({ width: '', height: '30', src: 'images/incomeLogoLgGray.png' });
                callback && callback(false);
            }
        }
    },
    openClose: function (type, callback) {
        var tipo = (type == 'open') ? ' apertura' : ' cierre';
        var options = {
            title: 'Ingrese el monto de' + tipo,
            operatorbtn: '-',
            nType: 'qty'
        }

        var tipo = (type == 'open') ? 'la apertura' : 'el cierre';

        numberPad(options, function (str) {
            if (str !== false) {//not dismissed modal
                var processIt = false;
                if (str == 0) {
                    ncmAlerts.alert({ "title": "¿Desea realizar " + tipo + " con " + ncmMaths.setCurrency('symbol') + "0?", type: 'confirm' }, function (result) {
                        if (result) {
                            ncmDrawerManager.submit(str, type, callback);
                        }
                    });
                } else if (ncmHelpers.validity(str) || str < 1) {//si es valido o 0
                    var str = ncmMaths.parseFloatSafe(str);
                    ncmDrawerManager.submit(str, type, callback);
                } else {
                    ncmAlerts.toast('Valor incorrecto', 'warning');
                }

                if (type != 'open') {
                    ncmDrawerManager.closedTotal = str;
                }
            }
        });
    },
    submit: function (str, type, callback) {
        var data = { 'type': type, 'date': getFullDateAndTime(), 'amount': str, 'outlet': ncmTransactions.cOutletData().name, 'register': ncmTransactions.cRegisterData().name, 'user': ncmAuth.activeUser.name, 'timestamp': time() };
        var store = { 'openCloseDrawer': data, 'uid': ncmHelpers.generateUid() };
        ncmHttp.sendDataToServer(store, function (back) {
            if (back) {
                callback && callback();
            } else {
                ncmAlerts.nativeAlert('No se pudo realizar ' + tipo + ', vuelva a intentar en un momento', 'danger');
            }
        });
    },
    list: function (callback) {
        var url = masterUrl + 'load?l=' + ncmHttp.masterUrlParams({ load: 'loadDrawerList', json: 1 });

        ncmHttp.get({
            url: url,
            onSuccess: (data) => {
                callback && callback(data);
                ncmUIX.uiHeightsAndSpaces();
            },
            onFail: (data) => {
                ncmAlerts.nativeAlert('No pudimos obtener datos ' + data, 'danger');
            },
            type: 'json'
        });
    },
    ui: function () {

        ncmUIX.mustache($('#modalNarrow .imodal-body'), {}, $('#drawerTpl'));

        if (ncmDrawerManager.isOpen) {

            ncmDrawerManager.list(function (result) {
                result.data.fsubtotal = ncmMaths.formatNumber({ number: result.data.subtotal });
                result.data.ftotal = ncmMaths.formatNumber({ number: result.data.total });
                result.data.ftips = ncmMaths.formatNumber({ number: result.data.tips });
                result.data.freturns = ncmMaths.formatNumber({ number: result.data.returns });
                result.data.fdate = moment(result.data.date).format('dddd, D MMM YYYY [a las] H:MM');

                $.each(result.data.list, function (i, val) {
                    val.famount = ncmMaths.formatNumber({ number: val.amount });
                });

                ncmUIX.mustache($('#modalNarrow .imodal-body #loadExternalDrawerList'), result.data, $('#drawerInTpl'));
                if ((ncmGlobals.settings[0].blindDrawer > 0 && ncmAuth.activeUser.role > 2) || window.accessLevel == 'LOW') {
                    $('#modalNarrow .imodal-body #loadExternalDrawerList').hide();
                } else {
                    ncmDrawerManager.state('show');
                }

                checkPermissions();
                ncmEvents.a();
                ncmHelpers.onClickWrap('#printClosure', function () {
                    ncmPrinters.justPrint('closeRegPrint');
                });
            });


        } else {
            ncmDrawerManager.state('hide');
            ncmEvents.a();
        }
    },
    state: function (type) {
        if (type == 'show') {
            $('#openClosedSign').attr({ width: '', height: '70', src: window.masterUrl + 'images/openLight.png' });
            $('#logoSaleList').attr({ width: '', height: '30', src: window.masterUrl + 'images/incomeLogoLgGray.png' });

            $('.closeRegister, #printClosure').show();
            $('.openRegister').hide();
        } else {
            $('#loadExternalDrawerList').html('');
            $('#openClosedSign').attr({ width: '', height: '70', src: 'images/closedLight.png' });
            $('#logoSaleList').attr({ width: '', height: '70', src: 'images/closedLight.png' });
            $('.closeRegister, #printClosure').hide();
            $('.openRegister').show();
        }
    },
    isOpenClose: function (callback) {
        var url = masterUrl + 'load?l=' + ncmHttp.masterUrlParams({ load: 'loadDrawerList', chk: 1 });

        ncmHttp.get({
            url: url,
            onSuccess: function (data) {
                if (data.closed) {
                    ncmDrawerManager.isOpen = false;
                    ncmDrawerManager.state('hide');
                } else {
                    ncmDrawerManager.isOpen = true;
                    ncmDrawerManager.state('show');
                }
                callback && callback(ncmDrawerManager.isOpen);
            },
            onFail: function (data) {
                ncmDrawerManager.isOpen = false;
                ncmDrawerManager.state('hide');
                callback && callback(ncmDrawerManager.isOpen);
            },
            hideLoader: true,
            type: 'json'
        });
    },
    control: function (show) {

        if (window.appConfigObj[0].drawer) {

            ncmUIX.setPopupClass($('#modalNarrow .imodal-content'));
            ncmUIX.setLoadingPlaceHolder({ el: $('#modalNarrow .imodal-body'), lg: 'bg_drawer.png', xs: 'bg_drawer_xs.png' });

            imodaler({ element: $('#modalNarrow') });

            ncmDrawerManager.isOpenClose(function (drawerStatus) {
                ncmDrawerManager.ui();
            });

            checkPermissions();
            ncmEvents.a();

        } else {
            ncmAlerts.nativeAlert('Active la opción "Control de caja" en Ajustes');
        }
    }
};

