var copyTextToClipBoard = function ($el) {
    $element = $el[0];
    var range;

    if (document.selection) { // IE
        range = document.body.createTextRange();
        range.moveToElementText($element);
        range.select();
        document.execCommand("copy");
    } else if (window.getSelection) {
        range = document.createRange();
        range.selectNode($element);
        window.getSelection().removeAllRanges();
        window.getSelection().addRange(range);
        document.execCommand("copy");
    }

    setTimeout(function () {
        window.getSelection().removeAllRanges();
    }, 300);
};

var explodes = function (str, splt, jn, index) {
    index = (index > -1) ? index : false;

    if (ncmHelpers.validity(str, 'string') || str == ' ') {
        var splited = str.split(splt);
        if ($.type(jn) == 'string') {//force que no sea false para poder usar join sin espacio ''
            return splited.join(jn);
        }
        if (index > -1 && index !== false) {
            if (splited.length > 1) {
                return splited[index];
            } else {
                return splited[0];
            }
        } else {
            return splited;
        }
    } else {
        if (index > -1) {
            return '';
        } else {
            return [];
        }
    }
};

var displaySelectedTags = function (tags) {
    var orgTags = ncmHelpers.getValidObjectStr(ncmGlobals.settings[0].tags);
    //var itemTags  = window.itemsObj[i].tags;
    var tagsList = new Array();
    if (ncmHelpers.validity(tags, 'array')) {
        $.each(tags, function (k, v) {
            var indx = arraySearch(orgTags, 'tagid', v);
            tagsList.push(orgTags[indx].tagname);
        });
        return tagsList;
    } else {
        return [];
    }
};

var checkIfUrlDebug = function () {
    var field = 'debug';
    var url = window.location.href;
    if (url.indexOf('?' + field + '=') != -1)
        return true;
    else if (url.indexOf('&' + field + '=') != -1)
        return true;
    else if (window.encomInApp)
        return true;
    return false
}

