var ncmOnReady = function () {
    if (window.dontStart) {
        return false;
    }

    ncmTutorial.nuke();//reseteo para que no auto inicie al actualizar

    // Sentry removed

    if (!checkIfUrlDebug()) {
        if ('serviceWorker' in navigator) {
            console.log('CLIENT: service worker registration in progress.');
            navigator.serviceWorker.register('/cache-sw.php?' + Math.random()).then(function () {
                console.log('CLIENT: service worker registration complete.');
            }, function () {
                console.log('CLIENT: service worker registration failure.');
            });
        } else {
            console.log('CLIENT: service worker is not supported.');
        }
    }

    $(document).ready(function () {

        window.onbeforeunload = function () {
            ncmWebSockets.checkoutScreen();
            if (window.itemsObj.length > 0 || ncmStorage.getEntry('sync').length) {
                return true;
            } else {
                return null;
            }
        }

        ncmUIX.setDarkMode();

        splashManager('show', false, true);

        fastClic('show');

        ncmHelpers.setFingerPrint();

        conectivityAlertsManager(true, true);
        deviceType();

        //simple initial internet check for offline loading
        //window.isServerOnline = (!window.navigator.onLine) ? false : true;

        Offline.options = { checkOnLoad: true, checks: { xhr: { url: window.conexionChkUrl } } };
        Offline.on('up', function () {
            window.isServerOnline = true;
            //ncmDialogs.push('Conexión restablecida');
        });

        Offline.on('down', function () {
            window.isServerOnline = false;
            //ncmDialogs.push('Revise su conexión');
        });

        checkInternet();

        var checkInternetInval = window.setInterval(function () {//check internet cada 5 seg
            checkInternet();
        }, 10000);

        pluginExecute('network', function () {
            $(document).on("offline", function () {
                window.isServerOnline = true;
                //ncmDialogs.push('Conexión restablecida');
            });

            $(document).on("online", function () {
                window.isServerOnline = true;
                //ncmDialogs.push('Revise su conexión');
            });

            thalog('check screen orientation');

            if (isMobile.phone) {
                screen.orientation.lock('portrait');
            } else {
                screen.orientation.lock('landscape');
            }

        });

        if (isMobile.any) {
            var deviceHeight = $(window).height();
            var deviceWidth = $(window).width();

            if (isMobile.tablet) {
                if (deviceWidth < deviceHeight) {
                    deviceHeight = deviceWidth - 20;

                    if (isMobile.apple.tablet) {
                        //  deviceHeight = deviceWidth-40;
                    }
                }
            } else if (isMobile.phone) {
                if (deviceHeight < deviceWidth) {
                    //esta volteado, cambio, le quito 20px porque le suma del statusbar que no tiene horizontal
                    deviceHeight = deviceWidth - 20;
                }
            }

            ncmUIX.windowH = deviceHeight;

            $('.hidden-mobile').hide();
            $('.visible-mobile').show();


            $('.container .vbox').removeClass('m-t-lg');
            $('section.container').addClass('fullheight clear').addClass('m-b-n-md');
        } else {
            if ($(window).width() < 1400) {
                ncmUIX.windowH = $(window).height();
                $('.container .vbox').removeClass('m-t-lg');
            } else {
                ncmUIX.windowH = $(window).height() - 60;
            }

            $('.hidden-mobile').show();
            $('.visible-mobile').hide();
        }

        $('section.container').css('min-height', ncmUIX.windowH + 'px');

        loadToolTip({ trigger: "hover" });

        startRegister();

        // device detection
        /*$.get(window.conexionChkUrl,function(result){//si hay internet flagueo antes de iniciar
            if(ncmHelpers.ifIstrue(result)){
                window.isServerOnline = true;
            }else{
                window.isServerOnline = false;
            }

            startRegister();
        },function(){//si NO hay internet flagueo antes de iniciar
            window.isServerOnline = false;
            startRegister();
        });*/
    });
};

