                $('#printOrder').removeClass("selected").find('input').removeAttr('checked');
                $('#printDelivery').removeClass("selected").find('input').removeAttr('checked');
                $('#printWithdraw').removeClass("selected").find('input').removeAttr('checked');
                $('#printQuote').removeClass("selected").find('input').removeAttr('checked');
                $('#printReceipt').removeClass("selected").find('input').removeAttr('checked');
                $('#quickPrinter').removeClass("selected").find('input').removeAttr('checked');
                $('#RawBT').removeClass("selected").find('input').removeAttr('checked');
                $('#printCloseReg').removeClass("selected").find('input').removeAttr('checked');
